INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (1, 'holiday', 'Шаббат', 'שַׁבָּת', '**Шаббат** (שַׁבָּת) — еженедельный день отдыха, с захода солнца в пятницу до выхода трёх звёзд в субботу.
Традиции:
- Зажигание свечей (הַדְלָקַת נֵרוֹת)
- Кидуш над вином (קִידוּשׁ)
- Хала — субботний хлеб (חַלָּה)
- Субботняя трапеза с семьёй
- Запрет на работу и использование электричества (у религиозных)
Полезные фразы:
- שַׁבָּת שָׁלוֹם! (шабАт шалОм!) — Мирной субботы!
- שָׁבוּעַ טוֹב (шавУа тов) — Хорошей недели! (после шаббата)', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (2, 'holiday', 'Песах', 'פֶּסַח', '**Песах** (פֶּסַח) — праздник весны и исхода из Египта. Длится 7 дней (8 в диаспоре).
Традиции:
- Седер Песах (סֵדֶר פֶּסַח) — праздничная трапеза с чтением Агады
- Маца (מַצָּה) — пресный хлеб
- Четыре бокала вина
- Четыре вопроса (מַה נִשְׁתַּנָּה)
- Запрет на хамец (квасное)
Фразы: חַג פֶּסַח שָׂמֵחַ! (хаг пЕсах самЕах!) — Весёлого Песаха!', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (3, 'holiday', 'Ханука', 'חֲנוּכָּה', '**Ханука** (חֲנוּכָּה) — праздник света, 8 дней в декабре.
История: маккавеи отвоевали Храм, маленький кувшин масла горел 8 дней.
Традиции:
- Зажигание ханукии (חֲנוּכִּיָּה) — по свече каждый день
- Суфганиёт (סוּפְגָנִיּוֹת) — пончики
- Латкес (לְבִיבוֹת) — картофельные оладьи
- Дрейдл (סְבִיבוֹן) — волчок
Фразы: חַג חֲנוּכָּה שָׂמֵחַ! (хаг ханукА самЕах!)', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (4, 'holiday', 'Пурим', 'פּוּרִים', '**Пурим** (פּוּרִים) — весёлый праздник в марте.
История: царица Эстер спасла евреев от плана Амана.
Традиции:
- Чтение Мегилат Эстер (מְגִלַּת אֶסְתֵּר)
- Маскарад и костюмы (תַּחְפֹּשֶׂת)
- Мишлоах манот (מִשְׁלוֹחַ מָנוֹת) — подарки друг другу
- Гоменташен / озней Аман (אוזני המן) — треугольные печенья
Фразы: חַג פּוּרִים שָׂמֵחַ! (хаг пурИм самЕах!)', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (5, 'holiday', 'Рош ха-Шана и Йом Кипур', 'רֹאשׁ הַשָּׁנָה וְיוֹם כִּפּוּר', '**Рош ха-Шана** (רֹאשׁ הַשָּׁנָה) — еврейский Новый год (сентябрь-октябрь).
Традиции: шофар (бараний рог), яблоки с мёдом, гранат.
Фраза: !שָׁנָה טוֹבָה (шанА товА!) — Хорошего года!
**Йом Кипур** (יוֹם כִּפּוּר) — День Искупления, через 10 дней после Рош ха-Шана.
Самый святой день: 25-часовой пост, молитвы, белая одежда.
В Израиле: нет машин на дорогах, дети катаются на велосипедах.
Фраза: גְּמַר חֲתִימָה טוֹבָה (гмар хатимА товА) — Хорошей записи (в Книге Жизни)!', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (6, 'daily_life', 'Ульпан — школа иврита', 'אוּלְפָּן', '**Ульпан** (אוּלְפָּן) — интенсивные курсы иврита для репатриантов.
- 5 уровней: от Алеф (начинающий) до Хей (продвинутый)
- Обычно 5 дней в неделю, 4-5 часов в день
- Первый ульпан открылся в 1949 году
- Новые репатрианты имеют право на бесплатный ульпан
Полезные слова:
- מוֹרָה/מוֹרֶה (морА/морЕ) — учительница/учитель
- תַּלְמִיד/תַּלְמִידָה (талмИд/талмидА) — ученик/ученица
- שִׁעוּר (шиУр) — урок', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (7, 'daily_life', 'Армия (ЦАХАЛ)', 'צָה"ל', '**ЦАХАЛ** (צָה"ל — צְבָא הַהֲגָנָה לְיִשְׂרָאֵל) — Армия Обороны Израиля.
- Обязательная служба: 32 мес. (мужчины), 24 мес. (женщины)
- Служат с 18 лет
- После армии многие путешествуют (обычно в Индию или Южную Америку)
Слова:
- חַיָּל/חַיֶּלֶת (хайЯл/хайЕлет) — солдат/солдатка
- קַצִין (кацИн) — офицер
- מִילוּאִים (милуИм) — резервная служба
- יוֹם הַזִּכָּרוֹן (йом hа-зикарОн) — День памяти', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (8, 'daily_life', 'Кибуц и мошав', 'קִיבּוּץ וּמוֹשָׁב', '**Кибуц** (קִיבּוּץ) — коллективное поселение, основанное на идеях социализма.
- Первый кибуц: Дгания (1910)
- Сегодня ~270 кибуцев
- Многие приватизировались, но сохранили общинный дух
**Мошав** (מוֹשָׁב) — сельское поселение с индивидуальными хозяйствами.
- Более 400 мошавов
- Каждая семья ведёт своё хозяйство
Слова:
- חָבֵר קִיבּוּץ (хавЕр кибУц) — член кибуца
- חַקְלָאוּת (хаклаУт) — сельское хозяйство', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (9, 'daily_life', 'Шук (рынок)', 'שׁוּק', '**Шук** (שׁוּק) — восточный рынок, важная часть израильской культуры.
Известные рынки:
- שׁוּק מַחֲנֵה יְהוּדָה (шук маханЕ еhудА) — Иерусалим
- שׁוּק הַכַּרְמֶל (шук hа-кармЕль) — Тель-Авив
Культура торга: на шуке принято торговаться!
Полезные фразы:
- כַּמָּה זֶה עוֹלֶה? (кАма зе олЕ?) — Сколько это стоит?
- יָקָר מִדַּי! (якАр мидАй!) — Слишком дорого!
- תַּעֲשֶׂה לִי הַנָּחָה (таасЕ ли hанахА) — Сделай мне скидку', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (10, 'daily_life', 'Купат Холим', 'קוּפַּת חוֹלִים', '**Купат Холим** (קוּפַּת חוֹלִים) — организация медицинского обслуживания (ОМО).
В Израиле 4 купот холим:
- כְּלָלִית (клалИт) — крупнейшая
- מַכַּבִּי (маккАби)
- מְאוּחֶדֶת (меухЕдет)
- לְאוּמִּית (леумИт)
Каждый житель обязан состоять в одной из них.
Слова:
- רוֹפֵא מִשְׁפָּחָה (рофЕ мишпахА) — семейный врач
- מִרְשָׁם (миршАм) — рецепт
- תוֹר (тор) — очередь / запись к врачу', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (11, 'abbreviations', 'Популярные аббревиатуры', 'ר"ת נפוצים', 'В иврите аббревиатуры обозначаются знаком " (гершаим) перед последней буквой.
| Аббр. | Полная форма | Значение |
|-------|-------------|----------|
| ת"ז | תְּעוּדַת זֶהוּת | Удостоверение личности |
| צה"ל | צְבָא הַהֲגָנָה לְיִשְׂרָאֵל | ЦАХАЛ (армия) |
| בג"ץ | בֵּית מִשְׁפָּט גָּבוֹהַּ לְצֶדֶק | БАГАЦ (Верховный суд) |
| ב"ל | בִּטּוּחַ לְאוּמִי | Битуах Леуми (соцстрах) |
| מע"מ | מַס עֵרֶךְ מוּסָף | НДС |
| ד"ר | דוֹקְטוֹר | Доктор |
| ח"כ | חֲבֵר כְּנֶסֶת | Депутат Кнессета |
| רה"מ | רֹאשׁ הַמֶּמְשָׁלָה | Премьер-министр |
| עו"ד | עוֹרֵךְ דִּין | Адвокат |
| ת"א | תֵּל אָבִיב | Тель-Авив |', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (12, 'slang', 'Сленг и разговорные выражения', 'סלנג', 'Израильский иврит богат сленгом из арабского, английского и русского.
| Слово | Произн. | Значение |
|-------|---------|----------|
| יַאללָה | яАлла | Давай! / Пошли! (из арабского) |
| סַבָּבָה | сабАба | Круто! / Ок! (из арабского) |
| אַחְלָה | ахлА | Супер! / Отлично! (из арабского) |
| חָבַל עַל הַזְּמַן | хавАль аль hа-зман | Нереально круто! (букв. «жаль на время») |
| מַה קוֹרֶה | ма корЕ | Что нового? / Как дела? |
| כָּפָרָה | капарА | Дорогой/дорогая (ласково) |
| פְרֶייֶר | фрайЕр | Простак / лох |
| חַיָּים שֶׁלִּי | хайИм шелИ | Моя жизнь (обращение к любимому) |
| מַגְנִיב | магнИв | Круто! |
| בָּלָאגָן | балагАн | Бардак / хаос (из русского!) |
| לְסַדֵּר | лесадЕр | Уладить / устроить |
| דַּוְקָא | дАвка | Именно / назло / как раз |', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (13, 'slang', 'Полезные разговорные фразы', 'ביטויים שימושיים', 'Фразы, которые вы услышите каждый день в Израиле:
| Фраза | Произн. | Значение |
|-------|---------|----------|
| מַה שְׁלוֹמְךָ? | ма шломхА? | Как дела? (м.) |
| מַה נִשְׁמָע? | ма нишмА? | Что слышно? (= как дела?) |
| אֵין בְּעָיָה | эйн беайА | Нет проблем |
| בְּכֵיף | бекЕйф | С удовольствием |
| אֶפְשָׁר | эфшАр | Можно |
| אִי אֶפְשָׁר | и эфшАр | Нельзя |
| כָּל הַכָּבוֹד | коль hа-кавОд | Молодец! (букв. «вся честь») |
| לְאַט לְאַט | леАт леАт | Потихоньку / постепенно |
| רֶגַע | рЕга | Подожди секунду |
| סְלִיחָה | слихА | Извините / Простите |', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (14, 'society', 'Хай-тек и стартапы', 'הייטק וסטארט-אפים', '**Израиль — нация стартапов** (אומת הסטארט-אפ)
Израиль занимает одно из первых мест в мире по количеству стартапов на душу населения.
Ключевые факторы:
- **Подразделение 8200** (יחידה 8200) — элитное подразделение разведки, выпускники которого основывают компании
- **Хуцпа** (חוצפה) — дерзость и готовность бросить вызов авторитетам
- **Культура неудач** — провал стартапа не стигматизируется, а считается опытом
Известные израильские компании: Waze, Mobileye, Check Point, Wix, Monday.com
Полезные слова:
- יזם (язАм) — предприниматель
- משקיע (машкИа) — инвестор
- גיוס הון (гиюс hон) — привлечение капитала
- אקזיט (Экзит) — продажа стартапа', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (15, 'society', 'Система образования', 'מערכת החינוך', '**Система образования в Израиле:**
- **גן ילדים** (ган еладИм) — детский сад (3-6 лет, обязательный с 3 лет)
- **בית ספר יסודי** (бейт сЕфер есодИ) — начальная школа (1-6 класс)
- **חטיבת ביניים** (хативАт бейнАим) — средняя школа (7-9 класс)
- **תיכון** (тихОн) — старшая школа (10-12 класс)
- **בגרות** (багрУт) — аттестат зрелости (аналог ЕГЭ)
**Высшее образование:**
- 9 университетов: Еврейский (Иерусалим), Тель-Авивский, Технион (Хайфа) и др.
- Институт Вейцмана — один из лучших научных центров мира
- Учёба начинается после армии, т.е. в 21-23 года
Полезные фразы:
- סטודנט/סטודנטית (студЕнт/студЕнтит)
- תואר ראשון (тоАр ришОн) — бакалавр (B.A.)
- תואר שני (тоАр шенИ) — магистр (M.A.)', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (16, 'society', 'Израильская кухня', 'המטבח הישראלי', '**Израильская кухня** — плавильный котёл культур:
**Знаковые блюда:**
- **פלאפל** (фалАфель) — шарики из нута во фритюре, в пите
- **חומוס** (хУмус) — паста из нута с тхиной
- **שקשוקה** (шакшукА) — яичница в томатном соусе
- **סביח** (сабИх) — пита с баклажаном и яйцом
- **שווארמה** (шавАрма) — мясо на вертеле
**Традиции:**
- В пятницу все покупают חלה (халА) — субботний хлеб
- Израильский завтрак (ארוחת בוקר) — один из лучших в мире
- Кошерность (כשרות): разделение мясного и молочного
Фразы в ресторане:
- בתיאבון! (бетеавОн!) — Приятного аппетита!
- חשבון, בבקשה (хешбОн, бевакашА) — Счёт, пожалуйста', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (17, 'history', 'История государства Израиль', 'תולדות מדינת ישראל', '**Основные вехи:**
- **1897** — Первый сионистский конгресс (Теодор Герцль)
- **1917** — Декларация Бальфура
- **1947** — Резолюция ООН о разделе Палестины
- **1948** — Провозглашение независимости (יום העצמאות)
  - Давид Бен-Гурион зачитал Декларацию независимости 14 мая 1948
- **1967** — Шестидневная война (מלחמת ששת הימים)
- **1973** — Война Судного дня (מלחמת יום הכיפורים)
- **1979** — Мирный договор с Египтом
- **1993** — Соглашения Осло
- **1994** — Мирный договор с Иорданией
Ключевые слова:
- עצמאות (ацмаУт) — независимость
- שלום (шалОм) — мир
- מלחמה (милхамА) — война
- הסכם (hескЕм) — соглашение', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (18, 'geography', 'География Израиля', 'הגיאוגרפיה של ישראל', '**Израиль — маленькая страна с разнообразным ландшафтом:**
**Регионы:**
- **גליל** (галИль) — Галилея: горы, леса, Кинерет
- **שרון** (шарОн) — равнина Шарон: Тель-Авив, Герцлия
- **שפלה** (шфелА) — Шфела: низменность между горами и морем
- **נגב** (нЕгев) — пустыня Негев: 60% территории страны
- **ערבה** (аравА) — рифтовая долина: Мёртвое море, Эйлат
**Города:**
- ירושלים (Иерусалим) — столица, святой город трёх религий
- תל אביב (Тель-Авив) — деловой и культурный центр
- חיפה (Хайфа) — порт, Технион, Бахайские сады
- באר שבע (Беэр-Шева) — столица Негева
- אילת (Эйлат) — курорт на Красном море
Факт: Израиль — единственная страна, увеличившая число деревьев за XX век!', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (19, 'literature', 'Израильская литература', 'הספרות הישראלית', '**Великие израильские писатели:**
**ש"י עגנון** (Шмуэль Йосеф Агнон, 1888-1970)
- Нобелевская премия по литературе 1966
- Главные произведения: «Вчера-позавчера», «Простая история»
**עמוס עוז** (Амос Оз, 1939-2018)
- «Повесть о любви и тьме» — автобиографический роман
- Один из самых переводимых израильских авторов
**דוד גרוסמן** (Давид Гроссман, род. 1954)
- «Женщина бежит от известия» — о войне и потере
- «Будь моим ножом» — эпистолярный роман
**אתגר קרת** (Этгар Керет, род. 1967)
- Мастер коротких рассказов, юмор и абсурд
- «Внезапно стук в дверь» — мировой бестселлер
Полезные слова:
- סופר/סופרת (софЕр/софЕрет) — писатель/писательница
- רומן (ромАн) — роман
- סיפור קצר (сипУр кацАр) — рассказ', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (20, 'language', 'Возрождение иврита', 'תחיית השפה העברית', '**Иврит — единственный мёртвый язык, возрождённый для повседневного использования.**
**אליעזר בן-יהודה** (Элиэзер Бен-Йеhуда, 1858-1922) — отец современного иврита:
- Составил первый словарь современного иврита (17 томов)
- Его сын Бен-Цион — первый ребёнок, для которого иврит стал родным за ~1700 лет
- Создал тысячи новых слов: עיתון (газета), מילון (словарь), רכבת (поезд)
**Этапы возрождения:**
1. Библейский иврит (до 200 г. н.э.)
2. Мишнаитский иврит (200-500 г.)
3. Литургический период (500-1880) — только молитвы и тексты
4. Возрождение (1880-1948) — Бен-Йеhуда, первые школы на иврите
5. Государственный язык (1948-) — иврит как язык государства
Сегодня на иврите говорят ~9 млн человек. Академия иврита (האקדמיה ללשון העברית) продолжает создавать новые слова для современных понятий.', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (21, 'culture', 'Израильская музыка: от песен первопроходцев до Эден Голан', 'המוזיקה הישראלית', 'Израильская музыка — зеркало страны: многообразной, страстной, постоянно меняющейся.
## Песни Земли Израиля (שירי ארץ ישראל)
В первые десятилетия государства были популярны патриотические и лирические песни о природе, земле и строительстве нового общества. Наоми Шемер (נעמי שמר) написала «Золотой Иерусалим» (ירושלים של זהב) — неофициальный гимн, который знает каждый израильтянин.
## Восточная музыка (מוזיקה מזרחית)
С волной репатриации из стран Востока — Марокко, Йемена, Ирака — в Израиль пришла восточная музыка. Долгое время она считалась «несерьёзной», но сегодня мизрахи — мейнстрим. Зоар Аргов (זוהר ארגוב), «король мизрахи», стал национальной легендой. Современные звёзды: Омер Адам (עומר אדם), Эяль Голан (אייל גולן), Статик и Бен Эль.
## Рок и поп
Израильский рок начался в 70-х с группы «Каверет» (כוורת). Позже пришли Шалом Ханох (שלום חנוך) и Арик Айнштейн (אריק איינשטיין) — последнего называют «голосом Израиля». Современная сцена — инди, электроника, хип-хоп.
## Евровидение
Израиль побеждал на Евровидении четыре раза: Изхар Коэн (1978), Дана Интернешнл (1998), Нетта Барзилай (2018). Конкурс — важная часть поп-культуры.
## Полезные слова
| Иврит | Перевод |
|---|---|
| שיר | песня |
| זמר / זמרת | певец / певица |
| להקה | группа (музыкальная) |
| הופעה | выступление / концерт |
| תקליט | альбом / пластинка |
', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (22, 'society', 'ЦАХАЛ и израильское общество', 'צה"ל והחברה הישראלית', 'Армия обороны Израиля (צבא הגנה לישראל, צה"ל) — не просто вооружённые силы, а один из главных социальных институтов страны.
## Обязательная служба (שירות חובה)
В Израиле действует всеобщая воинская обязанность. Мужчины служат около 32 месяцев, женщины — около 24. Служба начинается в 18 лет, сразу после школы.
Исключения: ультраортодоксальные евреи (חרדים) получают отсрочку для учёбы в ешиве, арабские граждане не призываются (но могут добровольно), друзы и черкесы служат обязательно.
## Армия как «плавильный котёл» (כור היתוך)
В ЦАХАЛе встречаются люди из разных слоёв: репатрианты и уроженцы, религиозные и светские, выходцы из десятков стран. Многие находят в армии друзей на всю жизнь. Выражение «חברים לטיול» (друзья из похода) — символ армейской дружбы.
## Резервисты (מילואים)
После обязательной службы мужчины остаются резервистами до 40–45 лет. Каждый год их могут призвать на учения или дежурство.
## Армия и карьера
Службу в элитных подразделениях — особенно в технологическом 8200 (יחידה 8200) — высоко ценят в хай-тек индустрии. Многие стартапы основаны выпускниками этих подразделений.
## Полезные слова
| Иврит | Перевод |
|---|---|
| צבא | армия |
| חייל / חיילת | солдат / солдатка |
| שירות חובה | обязательная служба |
| מילואים | резервистская служба |
| בסיס | база |
| שחרור | демобилизация |
', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (23, 'media', 'Израильские СМИ: свобода слова и острые дискуссии', 'תקשורת ישראלית', '## Уникальный медиаландшафт
Израиль — маленькая страна, но медиаландшафт здесь поразительно насыщен. Десятки ТВ-каналов, несколько крупных газет, радиостанции на всех языках и бурная интернет-культура.
## Телевидение
Каналы 12 и 13 — коммерческие лидеры. «Кан 11» — общественное вещание. Программы-хиты: «Фауда» (פאודה) — сериал о спецназе, ставший мировым бестселлером. «Штисель» (שטיסל) — о жизни ультраортодоксальной семьи.
## Газеты
«Гаарец» (הארץ) — либеральная качественная газета, читает элита. «Едиот Ахронот» (ידיעות אחרונות) — массовая, самый большой тираж. «Маарив» (מעריב) — вечерняя газета с долгой историей.
## Цифровая революция
Подкасты, YouTube-каналы, TikTok — молодёжь давно ушла из ТВ. Израильские инфлюенсеры набирают миллионы подписчиков.
## Полезные слова
| Иврит | Перевод |
|---|---|
| כתבה | статья / репортаж |
| מהדורת חדשות | выпуск новостей |
| רייטינג | рейтинг |
| שידור | вещание |
', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (24, 'ecology', 'Экология Израиля: от капельного орошения до солнечных полей', 'אקולוגיה ישראלית', '## Водная революция
Израиль превратил водный кризис в технологический триумф. Капельное орошение (השקיה בטפטוף), изобретённое в кибуце Хацерим в 1960-х, произвело революцию в мировом сельском хозяйстве. Компания Netafim продаёт эту технологию в 110 стран.
## Опреснение
Пять заводов опреснения превратили Израиль из страны с дефицитом воды в страну с излишком. Завод «Сорек» — крупнейший в мире. Стоимость кубометра опреснённой воды упала настолько, что стала конкурентоспособной с природной водой.
## Переработка воды
Израиль перерабатывает 87% сточных вод — мировой рекорд. Очищенная вода идёт на сельское хозяйство.
## Вызовы
Мёртвое море мелеет на метр в год. Проект «Красное–Мёртвое» (канал из Эйлата) призван спасти ситуацию, но вызывает экологические споры.
## Полезные слова
| Иврит | Перевод |
|---|---|
| מים | вода |
| מדבר | пустыня |
| חקלאות | сельское хозяйство |
| שפכים | сточные воды |
| מיחזור | переработка |
', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (25, 'sports', 'Спорт в Израиле: от маккаби до олимпийских медалей', 'ספורט בישראל', '## Футбол — страсть нации
Футбол (כדורגל) — самый популярный вид спорта. Лига «Ал» — высший дивизион. Главные клубы: Маккаби Тель-Авив, Хапоэль Тель-Авив, Маккаби Хайфа, Бейтар Иерусалим. Дерби — это больше, чем спорт, это идентичность.
## Баскетбол
Маккаби Тель-Авив — шестикратный чемпион Евролиги, один из самых титулованных клубов Европы. Баскетбол (כדורסל) — второй по популярности вид спорта.
## Олимпийские игры
Израиль завоевал медали в дзюдо, парусном спорте и художественной гимнастике. Линой Ашрам (לינוי אשרם) — олимпийская чемпионка 2021 года.
## Массовый спорт
Тель-Авивский марафон, «Хилла» (велопробег), серфинг в Герцлии и кайтсерфинг в Эйлате — израильтяне ведут активный образ жизни.
## Полезные слова
| Иврит | Перевод |
|---|---|
| כדורגל | футбол |
| כדורסל | баскетбол |
| אליפות | чемпионат |
| מדליה | медаль |
| אצטדיון | стадион |
', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (26, 'culture', 'Израильское кино: от Ави Нешера до «Фауды»', 'הקולנוע הישראלי', '## Рождение индустрии
Израильское кино началось с документальных фильмов о строительстве государства. Первый игровой фильм — «Одед-странник» (עודד הנודד, 1932). В 60-е появился жанр «бурекас» — лёгкие комедии о восточных и западных евреях.
## Новая волна
В 2000-х израильское кино получило мировое признание:
- «Вальс с Баширом» (ואלס עם באשיר) — анимационный документальный фильм о Ливанской войне
- «Развод по-фуа-грински» (הסרט של גט) — драма о религиозном разводе
- «Фуда» (פאודה) — сериал о спецназе, ставший мировым хитом
- «Штисель» (שטיסל) — о жизни ультраортодоксальной семьи
## Особенности
Израильское кино отличается смелостью в обращении с болезненными темами: конфликт, армия, религия, идентичность. Режиссёры не боятся задавать неудобные вопросы.
## Полезные слова
| Иврит | Перевод |
|---|---|
| סרט | фильм |
| במאי | режиссёр |
| שחקן / שחקנית | актёр / актриса |
| סדרה | сериал |
| פרס | приз |
', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (27, 'language', 'Эволюция сленга: от «сабра» до «ялла-бай»', 'האבולוציה של הסלנג הישראלי', '## Язык как зеркало общества
Израильский сленг — живая летопись страны. Каждое поколение приносит свои слова, а старые уходят.
## Слои сленга
**Арабские заимствования:** ялла (יאללה = давай), сабаба (סבבה = отлично), ахлА (אחלה = здорово), хлАс (חלאס = хватит).
**Армейский сленг:** джобник (ג''ובניק = тыловой), курсант (קורסנט), тирОн (טירון = новобранец), сарАф (שרף = отслужил срок).
**Современный:** вАйб (ווייב = атмосфера), флОу (פלואו = плавность), лайф (לייף = жизнь в значении «круто живёт»).
## Уникальные выражения
- **ялла-бай** (יאללה-ביי) = «ну давай, пока» — арабское + английское
- **ма питОм** (מה פתאום) = «с чего вдруг» (несогласие)
- **стАм** (סתם) = просто так, без причины
- **балагАн** (בלגן) = бардак (от русского!)
## Полезные слова
| Иврит | Перевод |
|---|---|
| יאללה | давай / пошли |
| סבבה | отлично |
| אחלה | здорово |
| בלגן | бардак |
| סתם | просто так |
', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (28, 'philosophy', 'Израильская философия: от Бубера до Лейбовица', 'הפילוסופיה הישראלית', '## Мартин Бубер (1878–1965)
Философ диалога. Его книга «Я и Ты» (אני ואתה) — о том, что подлинное существование возможно только через встречу с Другим. Бубер преподавал в Еврейском университете и призывал к арабо-еврейскому сосуществованию.
## Йешаяху Лейбовиц (1903–1994)
Учёный-энциклопедист и провокатор. Религиозный еврей, который резко критиковал оккупацию. Его фраза «иудо-нацизм» (в адрес некоторых явлений) вызвала скандал. Считал, что религия и государство должны быть разделены.
## Ханна Арендт (1906–1975)
Хотя она не израильтянка, её влияние на израильскую мысль огромно. Концепция «банальности зла» (из процесса Эйхмана в Иерусалиме) изменила понимание Холокоста.
## Современность
Сегодня израильская философия исследует идентичность, мультикультурализм и этику в условиях конфликта. Университеты Тель-Авива, Иерусалима и Хайфы — центры философской мысли.
## Полезные слова
| Иврит | Перевод |
|---|---|
| פילוסוף | философ |
| דיאלוג | диалог |
| מוסר | этика / мораль |
| קיום | существование |
| ביקורת | критика |
', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (29, 'language', 'Академия иврита', 'האקדמיה ללשון העברית', '## Страж языка
Академия языка иврит (האקדמיה ללשון העברית) — верховный институт, определяющий нормы иврита. Основана в 1953 году как преемница Комитета языка иврит (ועד הלשון), созданного Элиэзером Бен-Иегудой в 1890 году.
## Задачи Академии
- **Создание неологизмов:** для каждого нового понятия Академия предлагает ивритское слово. Примеры: מחשב (компьютер, от ח.ש.ב — считать), מסוק (вертолёт, от ס.ק. — вертеть), סלולרי (мобильный, от סלול — проторённый).
- **Установление норм:** правописание, грамматика, произношение.
- **Словари:** издание Исторического словаря иврита (מילון ההיסטורי).
## Успехи и неудачи
Некоторые слова Академии вошли в язык мгновенно: מחשב (компьютер), חשמל (электричество), מזגן (кондиционер). Другие проиграли конкуренцию заимствованиям: народ говорит טלפון (а не שלוחית), אינטרנט (а не מרשתת), טאבלט (а не לוח מחשב).
## Языковой пуризм vs. реальность
Академия придерживается умеренного пуризма. Она не запрещает заимствования, но предлагает альтернативы. Иногда народ выбирает ивритское слово (חולצה вместо рубашки), иногда — иностранное (ג''ינס, а не מכנסי בד כחול).
Вечная дилемма: язык принадлежит Академии или народу?
## Полезные слова
| Иврит | Перевод |
|---|---|
| אקדמיה | академия |
| חידוש לשוני | неологизм |
| תקן | норма / стандарт |
| מילון | словарь |
| שאילה | заимствование |
', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (30, 'law', 'Правовая система: история', 'המערכת המשפטית: היסטוריה', '## Четыре слоя права
Израильская правовая система — уникальная мозаика из четырёх исторических слоёв.
### 1. Османское право (1517–1917)
До Первой мировой войны Эрец-Исраэль входила в Османскую империю. Земельное право (חוק הקרקעות) во многом основано на османском кодексе. По сей день часть земельных споров решается с привлечением османских документов и законов — на турецком языке!
### 2. Британское мандатное право (1917–1948)
Британский мандат принёс систему общего права (common law). Принцип прецедента, институт доверительной собственности (נאמנות), процессуальные нормы — всё это пришло из английского права. До 1980 года израильские суды могли ссылаться на британские прецеденты.
### 3. Еврейское право (משפט עברי)
Галахические принципы влияют на семейное право: брак и развод евреев — в юрисдикции раввинских судов (בתי דין רבניים). Понятия добросовестности, справедливости, защиты слабого — из талмудической традиции.
### 4. Израильское законодательство (с 1948)
Кнессет принимает законы, Верховный суд (בית המשפט העליון / בג"ץ) осуществляет конституционный контроль. Основные законы (חוקי יסוד) выполняют роль конституции, которой у Израиля формально нет.
## Полезные слова
| Иврит | Перевод |
|---|---|
| חוק | закон |
| בית משפט | суд |
| בית דין רבני | раввинский суд |
| חוק יסוד | основной закон |
| תקדים | прецедент |
| נאמנות | доверительная собственность |
', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (31, 'society', 'Современное общество', 'החברה הישראלית בת זמננו', '## Мозаика идентичностей
Израильское общество — одно из самых разнообразных в мире. На площади чуть больше Крыма живут девять миллионов человек из более чем ста стран мира.
## Религиозно-светская ось
- **Хилоним** (חילונים) — светские, около 40%. Основа тель-авивской культуры.
- **Масортиим** (מסורתיים) — традиционалисты, около 25%. Соблюдают выборочно: шаббат — не всегда, Йом Кипур — обязательно.
- **Датиим** (דתיים) — религиозные, около 15%. Национально-религиозный лагерь, часто в кипе сруге (כיפה סרוגה).
- **Харедим** (חרדים) — ультраортодоксы, около 13%. Отдельная система образования, особый уклад жизни.
## Этническое разнообразие
- **Ашкеназы** (אשכנזים) — выходцы из Европы и Америки
- **Мизрахим** (מזרחים) — выходцы из арабских стран и Ирана
- **Эфиопы** (יוצאי אתיופיה) — община Бета Исраэль
- **Русскоязычные** (דוברי רוסית) — около миллиона, крупнейшая волна 90-х
- **Арабы** (ערבים) — около 21% населения: мусульмане, христиане, друзы
## Политический спектр
Израильская политика не укладывается в простую шкалу «лево-право»:
- **Безопасность**: ястребы vs. голуби (по отношению к конфликту)
- **Экономика**: свободный рынок vs. социальное государство
- **Религия и государство**: разделение vs. галахическое государство
- **Идентичность**: гражданский национализм vs. этнический
## Вечные дилеммы
Еврейское и демократическое? Безопасность и свобода? Традиция и прогресс? Западная и ближневосточная идентичность? Израильское общество живёт в постоянном напряжении между полюсами — и, возможно, именно это напряжение делает его таким живым.
## Полезные слова
| Иврит | Перевод |
|---|---|
| חברה | общество |
| מגוון | разнообразие |
| זהות | идентичность |
| מתח | напряжение |
| דו-קיום | сосуществование |
| שסע | раскол / разлом |
', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (32, 'culture', 'Приветствия и повседневные фразы в Израиле', 'ברכות ושפה יומיומית', '# Приветствия и повседневные фразы в Израиле (ברכות ושפה יומיומית)
Израильская культура общения отличается непосредственностью и теплотой. Даже незнакомые люди могут обратиться друг к другу на «ты», а формальные обороты используются значительно реже, чем в русском языке.
## Основные приветствия
Самое универсальное приветствие — **шалом** (שָׁלוֹם, шалОм), что дословно означает «мир». Его используют и при встрече, и при прощании, в любое время суток. В неформальной обстановке часто говорят **хай** (הַי) — заимствование из английского. Утром можно сказать **бокер тов** (בֹּקֶר טוֹב, бОкер тов) — «доброе утро», а вечером — **эрев тов** (עֶרֶב טוֹב, Эрев тов). На «бокер тов» часто отвечают **бокер ор** (בֹּקֶר אוֹר, бОкер ор) — буквально «утро света».
При прощании используют **леhитраот** (לְהִתְרָאוֹת, леhитраОт) — «до свидания», буквально «до встречи». Среди молодёжи популярно **яла бай** (יַאלָּה בַּיי) — «ну, пока», где «яла» (יַאלָּה) — это арабское заимствование, означающее «давай, пошли».
## «Ма нишма?» — главный вопрос
Фраза **ма нишма?** (מָה נִשְׁמָע?, ма нишмА) — «как дела?» (буквально «что слышно?») — это, пожалуй, самое употребительное выражение в разговорном иврите. Стандартные ответы: **тов** (טוֹב) — «хорошо», **бесЕдер** (בְּסֵדֶר) — «в порядке», **мецуян** (מְצוּיָן) — «отлично». Есть и параллельная форма — **ма шломха?** (מָה שְׁלוֹמְךָ?, ма шломхА) при обращении к мужчине и **ма шломех?** (מָה שְׁלוֹמֵךְ?, ма шломЕх) — к женщине.
## Вежливость по-израильски
Слово **бевакаша** (בְּבַקָּשָׁה, бевакашА) означает и «пожалуйста» (просьба), и «пожалуйста» (ответ на «спасибо»), и «прошу вас» (приглашение). **Тода** (תּוֹדָה, тодА) — «спасибо», **тода раба** (תּוֹדָה רַבָּה) — «большое спасибо». **Слиха** (סְלִיחָה, слихА) — «извините», но также используется, чтобы привлечь внимание, как русское «простите» в значении «подскажите».
Израильтяне ценят прямоту (דוּגְרִיּוּת, дугриЮт) — арабское заимствование, означающее «говорить прямо, без обиняков». Эта черта может показаться грубой иностранцам, но для израильтян это проявление искренности и уважения.', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (33, 'culture', 'Израильская кухня и традиции Шаббата', 'מטבח ישראלי ומסורות שבת', '# Израильская кухня и традиции Шаббата (מטבח ישראלי ומסורות שבת)
Израильская кухня — это уникальное сочетание ближневосточных, средиземноморских и восточноевропейских традиций. Еда в Израиле — это не просто питание, а важная часть культурной идентичности.
## Уличная еда — душа израильского города
**Фалафель** (פָלָאפֶל, фалАфель) — жареные шарики из нута — считается неофициальным национальным блюдом. Его подают в пите (פִּיתָה, пИта) с хумусом (חוּמוּס, хУмус), тхиной (טְחִינָה, тхинА) — пастой из кунжута, салатом и острым соусом **схуг** (סְחוּג, схуг) — йеменской приправой из острого перца. **Шаварма** (שַׁוַּארְמָה, шавармА) — мясо, приготовленное на вертеле, — ещё одно культовое уличное блюдо.
**Хумус** заслуживает отдельного рассказа. Для израильтян это не просто закуска, а предмет национальной гордости. Есть специальные рестораны — **хумусиёт** (חוּמוּסִיָּה, хумусиЯ), где хумус подаётся с фулем (פוּל) — бобами, грибами или мясом. Едят его, макая питу или свежий хлеб.
## Шук — израильский рынок
**Шук** (שׁוּק, шук) — рынок — это сердце любого израильского города. Самые знаменитые: **Махане Иехуда** (מַחֲנֵה יְהוּדָה) в Иерусалиме, известный как «шук», и **Кармель** (כַּרְמֶל) в Тель-Авиве. На рынке торгуются — **лехиткахеах** (לְהִתְכַּחֵחַ, леhиткахЕах) — и это часть культуры.
## Шаббат — сердце недели
**Шаббат** (שַׁבָּת, шабАт) начинается в пятницу вечером с заходом солнца и заканчивается в субботу вечером. Даже нерелигиозные семьи часто собираются на **арухат Шаббат** (אֲרוּחַת שַׁבָּת) — субботний ужин. Зажигают свечи — **нерот Шаббат** (נֵרוֹת שַׁבָּת), произносят благословение над вином — **кидуш** (קִידּוּשׁ, кидУш), и над хлебом — **хала** (חַלָּה, халА). Традиционная хала — это плетёный хлеб.
В Шаббат общественный транспорт в большинстве городов не работает. Многие магазины и рестораны закрыты. Это время для семьи, отдыха и прогулок. В Тель-Авиве атмосфера более светская: кафе и бары работают, а пляжи заполнены людьми.
## Завтрак по-израильски
Израильский завтрак — **арухат бокер** (אֲרוּחַת בֹּקֶר, арухАт бОкер) — знаменит во всём мире. Это щедрая трапеза с салатом из свежих овощей, яйцами, множеством сыров — **гвинот** (גְּבִינוֹת, гвинОт), оливками, хумусом и свежим хлебом. Такой завтрак подают в каждом отеле и кафе.', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (34, 'culture', 'Еврейские праздники в Израиле', 'חגים יהודיים בישראל', '# Еврейские праздники в Израиле (חגים יהודיים בישראל)
Израильский календарь ритмически организован вокруг еврейских праздников (**хагим**, חַגִּים, хагИм). Они определяют не только религиозную, но и светскую жизнь страны: школьные каникулы, рабочий график, телепрограммы.
## Рош ха-Шана (רֹאשׁ הַשָּׁנָה, рош hа-шанА) — еврейский Новый год
Празднуется осенью (сентябрь-октябрь). Главные символы: звук **шофара** (שׁוֹפָר, шофАр) — рога барана, макание яблока в мёд со словами **шана това у-метука** (שָׁנָה טוֹבָה וּמְתוּקָה) — «хорошего и сладкого года». На праздничном столе — гранат (**римон**, רִימּוֹן, римОн) — символ плодородия, и голова рыбы — символ «быть головой, а не хвостом».
## Йом Кипур (יוֹם כִּיפּוּר, йом кипУр) — День Искупления
Самый священный день еврейского календаря. 25 часов полного поста. Вся страна замирает: не работает транспорт, закрыты все заведения, даже телевидение и радио прекращают вещание. Дети катаются на велосипедах по пустым шоссе — это стало отдельной традицией. Принято просить прощения у близких — **лифнот аль слиха** (לִפְנוֹת עַל סְלִיחָה).
## Суккот (סוּכּוֹת, сукОт) — Праздник шалашей
Через пять дней после Йом Кипура. Строят временные шалаши — **сукка** (סוּכָּה, сукА) — и едят в них в течение недели. Четыре вида растений (**арбаат hа-миним**, אַרְבָּעַת הַמִּינִים) — лулав (пальмовая ветвь), этрог (цитрон), мирт и ива.
## Ханука (חֲנוּכָּה, ханукА) — Праздник огней
Восемь дней зажигают **ханукию** (חֲנוּכִּיָּה) — девятисвечник. Каждый вечер добавляют по одной свече. Едят **суфганиёт** (סוּפְגָּנִיּוֹת, суфганиЁт) — пончики с джемом и **левивот** (לְבִיבוֹת, левивОт) — картофельные оладьи, так как блюда готовятся на масле в память о чуде.
## Песах (פֶּסַח, пЕсах) — Пасха
Весенний праздник освобождения из Египта. Семь дней не едят **хамец** (חָמֵץ, хамЕц) — квасное. Центральное событие — **сЕдер** (סֵדֶר) — праздничная трапеза с чтением **Агады** (הַגָּדָה, hагадА) — рассказа об Исходе. Перед Песахом проводят генеральную уборку дома.', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (35, 'culture', 'Служба в армии — ЦАХАЛ и израильское общество', 'צה"ל והחברה הישראלית', '# Служба в армии — ЦАХАЛ и израильское общество (צה"ל והחברה הישראלית)
Армия обороны Израиля — **ЦАХАЛ** (צָהָ"ל, цАhаль — аббревиатура от צְבָא הַהֲגָנָה לְיִשְׂרָאֵל, цва hа-hаганА ле-исраЭль) — играет уникальную роль в израильском обществе. Это не просто военная структура, а институт социализации, формирующий национальную идентичность.
## Призыв — обязанность и привилегия
В Израиле действует всеобщая воинская обязанность — **гиюс хова** (גִּיּוּס חוֹבָה, гиЮс ховА). Мужчины служат 32 месяца, женщины — 24 месяца. Призывной возраст — 18 лет. Юноши и девушки, заканчивающие школу, получают **цав ришон** (צַו רִאשׁוֹן, цав ришОн) — первую повестку на медицинскую и психологическую проверку.
Отказ от службы крайне редок и воспринимается обществом неоднозначно. Существуют освобождения для ультраортодоксальных евреев — **харедим** (חֲרֵדִים, харедИм), арабских граждан и по медицинским показаниям.
## Боевые и небоевые подразделения
Элитные подразделения — **саерет** (סַיֶּרֶת, саЕрет) — предмет особого престижа. Самые известные: **Саерет Маткаль** (סַיֶּרֶת מַטְכַּ"ל) — генштабовская разведка, **Голани** (גּוֹלָנִי), **Гивати** (גִּבְעָתִי). Не все служат в боевых частях: многие попадают в технологические подразделения, например **8200** (יְחִידָה 8200, йехидА шмонЭ матАим) — подразделение радиоэлектронной разведки, выпускники которого часто основывают стартапы.
## Милуим — резервистская служба
После обязательной службы мужчины остаются резервистами — **милуимникИм** (מִילוּאִימְנִיקִים). Ежегодные сборы — **милуим** (מִילוּאִים, милуИм) — могут длиться несколько недель. Работодатель обязан сохранить рабочее место.
## Армия как плавильный котёл
ЦАХАЛ называют **кур hа-итух** (כּוּר הַהִתּוּךְ, кур hа-итУх) — «плавильный котёл». Здесь встречаются выходцы из разных стран, социальных слоёв и культурных традиций. Армейская дружба — **хаверут цваит** (חֲבֵרוּת צְבָאִית) — часто становится основой деловых и личных связей на всю жизнь. Многие израильские политики и бизнесмены познакомились во время службы.', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (36, 'culture', 'Кибуц — коллективная мечта и её трансформация', 'הקיבוץ — החלום הקולקטיבי', '# Кибуц — коллективная мечта и её трансформация (הקיבוץ — החלום הקולקטיבי)
**Кибуц** (קִיבּוּץ, кибУц) — уникальная форма коллективного поселения, не имеющая аналогов в мире. Зародившееся в начале XX века, движение кибуцев сыграло ключевую роль в создании Государства Израиль.
## Истоки: идеализм и пионерство
Первый кибуц — **Дгания** (דְּגַנְיָה, дганьЯ) — был основан в 1910 году на берегу озера Кинерет. Молодые еврейские иммигранты — **халуцим** (חַלוּצִים, халуцИм), «первопроходцы» — стремились создать новое общество на принципах равенства, коллективного труда и общей собственности.
В классическом кибуце не существовало частной собственности. Всё принадлежало общине: дома, одежда, даже подарки, полученные от родственников. Дети воспитывались в **бейт йеладим** (בֵּית יְלָדִים, бейт йеладИм) — «детском доме», отдельно от родителей, которых видели несколько часов в день.
## Экономика и быт
Кибуц функционировал как единый хозяйственный организм. Решения принимались на общем собрании — **асефа клалит** (אֲסֵפָה כְּלָלִית, асефА клалИт). Члены кибуца — **хаверим** (חֲבֵרִים, хаверИм) — не получали зарплату; все потребности обеспечивала община. Питались в общей столовой — **хадар охель** (חֲדַר אֹכֶל, хадАр Охель). Работали в сельском хозяйстве, позже — на фабриках и в сфере туризма.
## Кризис и приватизация
С 1980-х годов классическая модель кибуца переживает кризис. Экономические трудности, смена поколений и индивидуалистические ценности привели к **шинуй** (שִׁינּוּי, шинУй) — трансформации. Большинство кибуцев прошли через **hафрата** (הַפְרָטָה, hафратА) — приватизацию: ввели дифференцированную оплату труда, позволили частное владение жильём.
## Кибуц сегодня
Сегодня в Израиле около 270 кибуцев, в которых живёт около 170 тысяч человек. Различают **кибуц шитуфи** (קִיבּוּץ שִׁיתּוּפִי) — традиционный коммунальный, и **кибуц митхадеш** (קִיבּוּץ מִתְחַדֵּשׁ) — обновлённый. Многие кибуцы стали привлекательными для молодых семей благодаря безопасности, зелени и общинному духу — **руах кеhилатит** (רוּחַ קְהִלָּתִית).', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (37, 'culture', 'Алия — репатриация в Израиль', 'עלייה לישראל', '# Алия — репатриация в Израиль (עלייה לישראל)
**Алия** (עֲלִיָּה, алиЯ) — буквально «восхождение» — это переезд евреев в Землю Израиля. Этот термин несёт глубокий символический смысл: переезд в Израиль воспринимается не как эмиграция, а как духовный подъём.
## Волны алии: исторический обзор
Массовая иммиграция в Палестину началась в конце XIX века. Выделяют несколько волн:
- **Первая алия** (1882–1903) — из Российской империи после погромов
- **Вторая алия** (1904–1914) — идеалисты-социалисты, основатели кибуцев
- **Третья алия** (1919–1923) — после Первой мировой войны
- **Четвёртая алия** (1924–1929) — из Польши, развитие городов
- **Пятая алия** (1929–1939) — бегство от нацизма из Германии
После создания государства в 1948 году был принят **Хок hа-Швут** (חֹק הַשְּׁבוּת, хок hа-швУт) — Закон о возвращении, дающий каждому еврею право на репатриацию.
## Большая алия из СССР и СНГ
Крупнейшая волна — **алия из Советского Союза** в 1990-х годах. Около миллиона человек переехали в Израиль за десятилетие. Их называли **олим хадашим** (עוֹלִים חֲדָשִׁים, олИм хадашИм) — «новые репатрианты». Эта алия радикально изменила израильское общество: привезла учёных, музыкантов, инженеров, врачей. Русский язык стал третьим по распространённости в стране.
## Абсорбция — первые шаги
Процесс интеграции называется **клита** (קְלִיטָה, клитА) — «абсорбция». Новые репатрианты получают **саль клита** (סַל קְלִיטָה, саль клитА) — «корзину абсорбции» — денежную помощь от государства. Первый шаг — изучение иврита в **ульпане** (אוּלְפָּן, ульпАн) — языковой школе для взрослых, обычно пятимесячный интенсивный курс.
## «Тошав хозер» и современные тенденции
Существует и обратное явление — **йерида** (יְרִידָה, йеридА) — «спуск», эмиграция из Израиля. Тех, кто уехал и вернулся, называют **тошав хозер** (תּוֹשָׁב חוֹזֵר, тошАв хозЕр) — «возвращающийся житель». В последние годы растёт алия из Франции, Украины, России и стран Латинской Америки.
## Культурное влияние алии
Каждая волна алии обогатила израильскую культуру. Выходцы из Марокко принесли традицию **мимуна** (מִימוּנָה, мимУна) — праздника после Песаха. Йеменские евреи — уникальные песнопения и кулинарию. Русскоязычная алия создала театры, газеты и изменила музыкальную сцену. Эфиопские евреи — **бейта Исраэль** (בֵּיתָא יִשְׂרָאֵל) — добавили новые краски в национальную мозаику.', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (38, 'culture', 'Политическая система Израиля', 'המערכת הפוליטית בישראל', '# Политическая система Израиля (המערכת הפוליטית בישראל)
Израиль — парламентская демократия с многопартийной системой. Политическая жизнь страны отличается высокой интенсивностью и часто становится предметом оживлённых споров за каждым семейным столом.
## Кнессет — парламент Израиля
**Кнессет** (הַכְּנֶסֶת, hа-кнЕсет) — однопалатный парламент, состоящий из 120 депутатов — **хаврей Кнессет** (חַבְרֵי כְּנֶסֶת, хаврЕй кнЕсет), сокращённо **хак** (ח"כ). Выборы проходят по пропорциональной системе: избиратели голосуют за партийные списки, а не за отдельных кандидатов. Электоральный барьер — **ахуз хасима** (אָחוּז חֲסִימָה, ахУз хасимА) — составляет 3,25%.
Из-за многопартийности ни одна партия никогда не получала абсолютного большинства. Поэтому всегда формируются коалиции — **коалиция** (קוֹאָלִיצְיָה, коалИция). Переговоры о формировании правительства могут длиться неделями.
## Премьер-министр и правительство
Главу правительства — **рош hа-мемшала** (רֹאשׁ הַמֶּמְשָׁלָה, рош hа-мемшалА) — назначает **наси** (נָשִׂיא, насИ) — президент (церемониальная должность). Формирование правительства — **hаркават мемшала** (הַרְכָּבַת מֶמְשָׁלָה) — поручается лидеру партии, имеющей наилучшие шансы собрать коалицию из 61+ мандатов.
Правительство — **мемшала** (מֶמְשָׁלָה, мемшалА) — состоит из министров (**сарим**, שָׂרִים). Ключевые министерства: **мисрад hа-битахон** (מִשְׂרַד הַבִּטָּחוֹן) — Минобороны, **мисрад hа-хуц** (מִשְׂרַד הַחוּץ) — МИД, **мисрад hа-осар** (מִשְׂרַד הָאוֹצָר) — Минфин.
## Политические лагеря
Израильская политика традиционно делится на **ямин** (יָמִין, ямИн) — правый лагерь, и **смоль** (שְׂמֹאל, смоль) — левый. Правые обычно занимают более жёсткую позицию по вопросам безопасности и территорий, левые — выступают за мирные переговоры. Существует и **мерказ** (מֶרְכָּז) — центр. Важную роль играют религиозные партии — как ультраортодоксальные, так и национально-религиозные — **мафдаль** (מַפְדָּ"ל).
## Особенности политической культуры
Израильтяне чрезвычайно политически активны. Явка на выборах — **ахуз hа-hацбаа** (אָחוּז הַהַצְבָּעָה) — обычно превышает 65%. Политические дискуссии ведутся повсюду: на работе, на семейных обедах, в такси. Выражение **маца hа-арец** (מַצָּב הָאָרֶץ, мацАв hа-Арец) — «положение дел в стране» — одна из самых частых тем для разговора.', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (39, 'culture', 'Система образования в Израиле', 'מערכת החינוך בישראל', '# Система образования в Израиле (מערכת החינוך בישראל)
Образование в Израиле — **хинух** (חִינּוּךְ, хинУх) — является обязательным и бесплатным с 3 до 18 лет. Система отличается многообразием потоков и высоким уровнем вовлечённости родителей.
## Структура школьного образования
Система делится на три ступени:
- **Бейт сефер йесоди** (בֵּית סֵפֶר יְסוֹדִי, бейт сЕфер йесодИ) — начальная школа (1–6 классы)
- **Хативат бейнаим** (חֲטִיבַת בֵּינַיִם, хативАт бейнАим) — средняя школа (7–9 классы)
- **Тихон** (תִּיכוֹן, тихОн) — старшая школа (10–12 классы)
Существуют четыре потока: государственный (**мамлахти**, מַמְלַכְתִּי), государственно-религиозный (**мамлахти-дати**, מַמְלַכְתִּי דָּתִי), ультраортодоксальный и арабский.
## Багрут — аттестат зрелости
Главная цель старшей школы — сдача экзаменов на **багрут** (בַּגְרוּת, багрУт) — аттестат зрелости. Это серия экзаменов по выбранным предметам на разных уровнях сложности — **йехидот лимуд** (יְחִידוֹת לִימוּד, йехидОт лимУд) — «учебные единицы» (от 1 до 5). Пять единиц по математике (**хамеш йехидот математика**) — считается престижным.
Без багрута сложно поступить в университет. По статистике, около 70% выпускников получают полный аттестат.
## Высшее образование
В Израиле восемь университетов. Самые престижные: **Технион** (טֶכְנִיּוֹן) в Хайфе — технологический институт, **Еврейский университет** (הָאוּנִיבֶרְסִיטָה הָעִבְרִית, hа-университА hа-иврИт) в Иерусалиме, **Тель-Авивский университет** (אוּנִיבֶרְסִיטַת תֵּל אָבִיב). Существуют также **михлалот** (מִכְלָלוֹת, михлалОт) — колледжи.
Особенность: большинство студентов поступают в вуз после армии, в 21–23 года. Многие предварительно берут «год отдыха» — **шнат нешира** или путешествуют по Южной Америке или Юго-Восточной Азии — **hа-тиюль hа-гадоль** (הַטִּיּוּל הַגָּדוֹל) — «большое путешествие».
## Неформальное образование
Важную роль играют молодёжные движения — **тнуот ноар** (תְּנוּעוֹת נוֹעַר, тнуОт нОар). Самые известные: **hа-Цофим** (הַצּוֹפִים) — Скауты, **hа-Ноар hа-Овед** (הַנּוֹעַר הָעוֹבֵד) — Рабочая молодёжь. Они формируют лидерские качества и общественную ответственность.', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (40, 'culture', 'Система здравоохранения в Израиле', 'מערכת הבריאות בישראל', '# Система здравоохранения в Израиле (מערכת הבריאות בישראל)
Израильская система здравоохранения считается одной из лучших в мире. Закон о государственном медицинском страховании обеспечивает всем гражданам доступ к широкому спектру медицинских услуг.
## Купот холим — больничные кассы
Основа системы — четыре **купот холим** (קוּפּוֹת חוֹלִים, купОт холИм) — больничные кассы, в одной из которых обязан состоять каждый гражданин:
- **Клалит** (כְּלָלִית, клалИт) — крупнейшая, обслуживает около 50% населения
- **Маккаби** (מַכַּבִּי, макАби) — вторая по размеру
- **Меухедет** (מְאוּחֶדֶת, меухЕдет)
- **Леумит** (לְאוּמִית, леумИт)
Каждый месяц из зарплаты удерживается **мас бриют** (מַס בְּרִיאוּת, мас бриЮт) — налог на здравоохранение. Этот взнос обеспечивает базовую «корзину здоровья» — **саль бриют** (סַל בְּרִיאוּת, саль бриЮт).
## Врач первичного звена
Первый контакт пациента — **рофе мишпаха** (רוֹפֵא מִשְׁפָּחָה, рофЕ мишпахА) — семейный врач. Он работает в поликлинике — **мирпаа** (מִרְפָּאָה, мирпаА). Для визита к специалисту — **рофе мумхе** (רוֹפֵא מוּמְחֶה, рофЕ мумхЕ) — необходимо направление — **ихпуль** (הִפְנָיָה, hафнаЯ). Запись к врачу обычно через приложение купат холим.
## Больницы и экстренная помощь
Крупнейшие больницы — **батей холим** (בָּתֵּי חוֹלִים, батЕй холИм): **Ихилов** (в Тель-Авиве), **Хадасса** (הֲדַסָּה, в Иерусалиме), **Рамбам** (רַמְבַּ"ם, в Хайфе), **Шиба** (שִׁיבָא, в Рамат-Гане) — крупнейшая больница на Ближнем Востоке.
Скорая помощь — **Маген Давид Адом** (מָגֵן דָּוִד אָדוֹם, магЕн давИд адОм) — «Красный Щит Давида», израильский аналог Красного Креста. Номер вызова — 101. Приёмный покой — **хедер миюн** (חֶדֶר מִיּוּן, хЕдер миЮн) — «комната сортировки».
## Достижения и вызовы
Израиль лидирует в мире по продолжительности жизни (более 83 лет), количеству врачей на душу населения и медицинским инновациям. Страна — мировой центр медицинского туризма, особенно в области ЭКО — **hафрая хуц-гуфит** (הַפְרָיָה חוּץ-גוּפִית), онкологии и кардиологии. Главный вызов — очереди к специалистам и неравенство в доступе между центром и периферией.', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (41, 'culture', 'Нация стартапов — хайтек-индустрия Израиля', 'אומת הסטארט-אפ — תעשיית ההייטק', '# Нация стартапов — хайтек-индустрия Израиля (אומת הסטארט-אפ — תעשיית ההייטק)
Израиль называют **умат hа-стартап** (אוּמַּת הַסְטַארְט-אַפּ, умАт hа-стАрт-ап) — «нация стартапов». При населении менее 10 миллионов человек страна занимает первое место в мире по количеству стартапов на душу населения и привлечённому венчурному капиталу.
## Экосистема инноваций
Израильский хайтек — **hайтек** (הַייטֶק) — сконцентрирован в нескольких кластерах. Главный — **Кремниевое вади** (по аналогии с Кремниевой долиной), включающий Тель-Авив, Герцлию и Раанану. Район Герцлии **Питуах** (הֶרְצְלִיָּה פִּיתּוּחַ) — место расположения штаб-квартир многих международных технологических компаний.
Ключевые факторы успеха:
- **Подразделение 8200** (יְחִידָה 8200) — выпускники военной разведки формируют костяк кибербезопасности и технологического сектора
- **Хуцпа** (חוּצְפָּה, хуцпА) — дерзость и готовность оспаривать авторитеты, характерная для израильской культуры
- **Толерантность к провалу** — в израильской бизнес-культуре неудача рассматривается как опыт, а не как клеймо
- **Многообразие** — инженеры-репатрианты привносят разные перспективы
## Ключевые секторы
**Кибербезопасность** — **сайбер** (סַייבֶּר, сАйбер) — Израиль занимает второе место в мире после США. Компании Check Point, CyberArk, Wiz стали глобальными лидерами. **Финтех** (פִינְטֶק) — финансовые технологии, **агритех** (אַגְרִיטֶק) — сельскохозяйственные технологии (капельное орошение — израильское изобретение), **медтех** (מֶדְטֶק) — медицинские технологии.
## Хайтек и общество
Хайтек-сектор создаёт около 15% ВВП и обеспечивает 10% рабочих мест, но при этом генерирует около 50% экспорта. Средняя зарплата — **маскорет** (מַשְׂכֹּרֶת, маскОрет) — в хайтеке в 2,5 раза выше средней по стране. Это создаёт **пеар** (פְּעַר, пеАр) — разрыв — между «нацией стартапов» и «нацией Шаббата», между центром и периферией.
Правительство активно поддерживает инновации через **Управление инноваций** — **Рашут hа-хидуш** (רָשׁוּת הַחִדּוּשׁ, рашУт hа-хидУш) — и программы инкубаторов. Ежегодные технологические конференции — **DLD Tel Aviv**, **Cybertech** — привлекают тысячи участников со всего мира.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (42, 'culture', 'Общественные дебаты в Израиле: религия, идентичность, равенство', 'ויכוחים חברתיים בישראל', '# Общественные дебаты в Израиле (ויכוחים חברתיים בישראל)
Израильское общество находится в состоянии постоянного диалога — а нередко и острого спора — по ряду фундаментальных вопросов. Эти **викухим** (וִיכּוּחִים, викухИм) — дискуссии — отражают сложность страны, объединяющей людей с разными ценностями, традициями и видением будущего.
## Религия и государство (דָּת וּמְדִינָה)
Центральный вопрос — отношения между **дат** (דָּת, дат) — религией — и **медина** (מְדִינָה, мединА) — государством. В Израиле нет отделения религии от государства: бракосочетание — **нисуин** (נִישּׂוּאִין, нисуИн) — возможно только через религиозные институты. Раввинат — **hа-рабанут** (הָרַבָּנוּת, hа-рабанУт) — контролирует вопросы женитьбы, развода, конверсии и кашрута.
Светские граждане — **хилоним** (חִילוֹנִים, хилонИм) — выступают за гражданский брак, общественный транспорт по субботам, призыв ультраортодоксов в армию. Религиозные — **датиим** (דָּתִיִּים, датиИм) — защищают статус-кво.
## Протест «палаток» и социальная справедливость
В 2011 году вспыхнул массовый социальный протест — **михаат hа-охалим** (מְחָאַת הָאוֹהָלִים, мехаАт hа-оhалИм) — «протест палаток». Сотни тысяч людей вышли на улицы с требованием **цедек хевратИ** (צֶדֶק חֶבְרָתִי) — социальной справедливости. Главные требования: доступное жильё, снижение стоимости жизни — **йокер hа-хаим** (יוֹקֶר הַחַיִּים, йОкер hа-хаИм), реформа образования и здравоохранения.
## Ашкеназы и мизрахим
Историческое напряжение между **ашкеназим** (אַשְׁכְּנַזִים) — выходцами из Европы, и **мизрахим** (מִזְרָחִים, мизрахИм) — из восточных стран (Марокко, Ирак, Йемен). Хотя разрыв сократился, **ха-пеар hа-адатИ** (הַפְּעַר הָעֲדָתִי) — этническое неравенство — остаётся темой обсуждения в сферах образования, экономики и политики.
## Центр и периферия
Разрыв между богатым центром — **hа-мерказ** (הַמֶּרְכָּז) — (Тель-Авив, Герцлия) и **hа-перифЕрия** (הַפֶּרִיפֶרְיָה) — периферией (юг, север) — в уровне зарплат, качестве образования, доступе к здравоохранению и культурным ресурсам. Город развития — **ир питуах** (עִיר פִּיתּוּחַ, ир питУах) — обозначает периферийные города, которые нуждаются в дополнительных инвестициях.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (43, 'culture', 'Израильская литература: от Агнона до наших дней', 'הספרות הישראלית: מעגנון ועד ימינו', '# Израильская литература: от Агнона до наших дней (הספרות הישראלית)
Израильская литература — **сифрут исраэлит** (סִפְרוּת יִשְׂרָאֵלִית, сифрУт исраэлИт) — одна из самых молодых и динамичных в мире. За неполное столетие она прошла путь от идеологической прозы первопоселенцев до полифонических романов мирового уровня.
## Поколение основателей: «Дор hа-Медина»
Писатели «поколения государства» — **дор hа-медина** (דּוֹר הַמְּדִינָה, дор hа-мединА) — начали публиковать в 1940-50-е. **Шмуэль Йосеф Агнон** (שמואל יוסף עגנון, шмуЭль йосЕф агнОн) — единственный ивритский нобелевский лауреат по литературе (1966). Его проза — сложное сплетение талмудического языка и модернистских приёмов.
**Амос Оз** (עמוס עוז, амОс оз) — самый переводимый израильский писатель. Его автобиографический роман «Повесть о любви и тьме» (סיפור על אהבה וחושך, сипУр аль аhавА ве-хОшех) стал классикой. Оз писал о кибуце, Иерусалиме, о разрыве между мечтой сионизма и реальностью.
## «Новая волна» и пост-сионизм
В 1980-90-е пришло поколение, переосмысляющее национальный нарратив. **Давид Гроссман** (דוד גרוסמן, давИд гросмАн) в романе «Смотри под: любовь» (עיין ערך: אהבה) описал жизнь палестинцев на оккупированных территориях. **Меир Шалев** (מאיר שלו, меИр шалЕв) создал магический реализм израильской деревни.
**Этгар Керет** (אתגר קרת, этгАр кЕрет) — мастер короткого рассказа — **сипур кацар** (סִיפּוּר קָצָר, сипУр кацАр). Его минималистичные, абсурдные тексты стали визитной карточкой новой израильской прозы.
## Поэзия — национальное достояние
Поэзия — **шира** (שִׁירָה, ширА) — занимает особое место. **Иехуда Амихай** (יהודה עמיחי, йеhудА амихАй) — величайший израильский поэт, превративший повседневный иврит в инструмент высокой лирики. **Рахель** (רחל) — поэтесса Второй алии, чьи стихи о Кинерете знает каждый школьник. **Натан Альтерман** (נתן אלתרמן) — поэт-трибун, чьи колонки в газете влияли на политику.
## Современная сцена
Современная литература отражает многоголосие общества. Пишут мизрахийские авторы — **софрим мизрахим** (סוֹפְרִים מִזְרָחִים), арабские граждане на иврите, русскоязычные репатрианты. **Аелет Гундар-Гошен** (אילת גונדר-גושן), **Рубик Розенталь** (רוביק רוזנטל), **Нево Оз** — голоса нового поколения. Израильская литература сегодня — это литература вопросов, а не ответов.', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (44, 'culture', 'Философская мысль Израиля: от Бубера до современности', 'הפילוסופיה הישראלית: מבובר ועד היום', '# Философская мысль Израиля (הפילוסופיה הישראלית: מבובר ועד היום)
Израильская философия — **филосОфия исраэлит** (פִילוֹסוֹפְיָה יִשְׂרָאֵלִית) — формировалась на пересечении еврейской традиции, европейской мысли и уникального опыта государственного строительства. Это не кабинетная дисциплина, а живой диалог с реальностью.
## Мартин Бубер: «Я и Ты»
**Мартин Бубер** (מרטין בובר, мАртин бУбер) — философ диалога, переехавший в Палестину в 1938 году. Его главный труд — **«Я и Ты»** («אני ואתה», анИ ве-атА) — противопоставляет два типа отношений: **Я-Ты** (אני-אתה) — подлинный диалог, встреча двух субъектов, и **Я-Оно** (אני-זה) — инструментальное отношение к другому как к объекту.
Бубер выступал за **двунациональное государство** и диалог с арабами. Его идеи оказали влияние на педагогику, психотерапию и теологию далеко за пределами Израиля.
## Йешаяху Лейбович: совесть нации
**Йешаяху Лейбович** (ישעיהו ליבוביץ'', йешаЯhу лЕйбович) — учёный-энциклопедист, биохимик и философ. Его острая критика оккупации после 1967 года, сформулированная в термине **«иудео-нацизм»**, вызвала бурю. Лейбович разделял религию и государство: по его мнению, превращение государства в сакральный объект — форма идолопоклонства — **авода зара** (עֲבוֹדָה זָרָה, аводА зарА).
## Ханна Арендт и её влияние
Хотя **Ханна Арендт** (חנה ארנדט) жила в США, её работы о **«банальности зла»** (בנאליות הרוע), написанные после процесса Эйхмана в Иерусалиме, стали центральными для израильского осмысления Холокоста — **Шоа** (שׁוֹאָה, шоА). Её тезис о том, что зло может быть бюрократическим и бездумным, остаётся предметом дискуссий.
## Современная израильская философия
Сегодня израильская философия охватывает широкий спектр направлений. **Ависхай Маргалит** (אבישי מרגלית, авишАй маргалИт) исследует «достойное общество» — **хевра мехубЕдет** (חֶבְרָה מְכוּבֶּדֶת) — общество, институты которого не унижают людей. **Моше Хальберталь** (משה הלברטל) работает на стыке философии права и еврейской мысли.
Израильские философы активно участвуют в этических дебатах — **викуах этИ** (וִיכּוּחַ אֶתִי) — от биоэтики до этики войны. Философский факультет **Еврейского университета** — один из сильнейших в мире. Философия в Израиле — не абстракция, а инструмент осмысления непростой реальности.', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (45, 'culture', 'Возрождение иврита: от мёртвого языка к живой речи', 'תחיית השפה העברית', '# Возрождение иврита (תחיית השפה העברית, тхиЯт hа-сафА hа-иврИт)
Возрождение иврита — **тхият hа-иврит** — один из самых поразительных лингвистических феноменов в истории. Язык, переставший быть разговорным около 200 года н. э., был «воскрешён» и стал родным для миллионов людей. Ни один другой язык не пережил подобной трансформации.
## Иврит до возрождения
После римского разрушения Иудеи иврит сохранялся как **лешон hа-кодеш** (לְשׁוֹן הַקֹּדֶשׁ, лешОн hа-кОдеш) — «святой язык»: язык молитвы, религиозных текстов и учёной переписки. Евреи в быту говорили на языках окружающих народов или на еврейских языках: **идиш** (אידיש) в Европе, **ладино** (לאדינו) на Пиренейском полуострове, **еврейско-арабский** на Востоке. Иврит оставался литературным языком, но разговорным — нет.
## Элиэзер Бен-Иехуда: человек и миссия
**Элиэзер Бен-Иехуда** (אֱלִיעֶזֶר בֶּן-יְהוּדָה, элиЭзер бен-йеhудА), настоящее имя Перельман, приехал в Палестину в 1881 году с идеей фикс: превратить иврит в живой разговорный язык. Он принял три принципа:
1. **Иврит дома** — говорить с женой и детьми только на иврите. Его сын **Бен-Цион** (בֶּן-צִיּוֹן) стал первым ребёнком Нового времени, для которого иврит был родным языком — **сафат эм** (שְׂפַת אֵם, сфат эм)
2. **Иврит в обществе** — требовать от окружающих общения на иврите
3. **Создание словаря** — монументальный словарь иврита в 17 томах
Бен-Иехуда создавал **хидушей лашон** (חִידּוּשֵׁי לָשׁוֹן, хидушЕй лашОн) — неологизмы — сотнями: «газета» — **итон** (עִיתּוֹן, итОн), «мороженое» — **глида** (גְּלִידָה, глидА), «полотенце» — **магевет** (מַגֶּבֶת, магЕвет).
## Битва языков
Возрождение не было неизбежным. В 1913 году разразилась **милхемет hа-сафот** (מִלְחֶמֶת הַשָּׂפוֹת, милхЕмет hа-сафОт) — «война языков». Немецкий филантропический фонд «Эзра» хотел ввести преподавание на немецком в Технионе. Учителя и ученики объявили забастовку. Иврит победил и утвердился как язык образования.
## От «высокого» к живому
Современный иврит — **иврит бат-зманЕну** (עִבְרִית בַּת-זְמַנֵּנוּ, иврИт бат-зманЕну) — значительно отличается от библейского. Он впитал влияния арамейского, арабского, идиша, русского и английского языков. **Академия языка иврит** — **hа-Академия ле-лашон иврит** (הָאָקָדֶמְיָה לַלָּשׁוֹן הָעִבְרִית) — занимается стандартизацией и созданием новых терминов, хотя разговорный язык часто опережает академические решения.', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (46, 'culture', 'Израильская идентичность: между Востоком и Западом', 'הזהות הישראלית: בין מזרח למערב', '# Израильская идентичность: между Востоком и Западом (הזהות הישראלית)
Вопрос **зеhут** (זְהוּת, зеhУт) — идентичности — находится в центре израильского самосознания. Кто такие израильтяне? Как соотносятся «еврейский» и «израильский»? Государство, построенное репатриантами из десятков стран, непрерывно ищет ответы на эти вопросы.
## «Новый еврей» — сабра
Сионистское движение стремилось создать **«адам хадаш»** (אָדָם חָדָשׁ) — «нового человека», противоположность «галутному еврею». Идеал — **цабар** (צַבָּר, цабАр) — «сабра», уроженец Израиля, названный по кактусовому плоду: колючий снаружи, сладкий внутри. Сабра — загорелый, физически крепкий, прямолинейный, привязанный к земле — антитеза бледному городскому интеллектуалу диаспоры.
Этот идеал доминировал в первые десятилетия государства, но постепенно был подвергнут критике как исключающий мизрахийский, диаспорный и религиозный опыт.
## Мозаика идентичностей
Современная израильская идентичность — это **мозаика** (פְּסִיפֵס, псифЕс, буквально «мозаика»). Основные оси самоопределения:
- **Светскость — религиозность**: от **хилони** (חִילוֹנִי) — полностью светского — до **хареди** (חֲרֵדִי) — ультраортодоксального. Между ними — **масорти** (מָסוֹרְתִּי, масортИ) — «традиционный» и **дати** (דָּתִי) — «религиозный».
- **Этническое происхождение**: **ашкенази** (אַשְׁכְּנַזִי) — европейские корни, **мизрахи** (מִזְרָחִי) — восточные, **эфиопский** (אתיופי), **русский** (רוּסִי, рУси) — как культурная идентичность выходцев из СССР/СНГ.
- **Политическая ориентация**: правый-левый, но также **пост-сионист** (פּוֹסְט-צִיּוֹנִי) и **нео-сионист** (נֵאוֹ-צִיּוֹנִי).
## «Исраэлиют» — израильскость
Понятие **исраэлиЮт** (יִשְׂרָאֵלִיּוּת, исраэлиЮт) — «израильскость» — описывает общую культурную идентичность, выходящую за рамки религии и этничности. Её элементы: армейский опыт, специфический юмор — **hумор исраэли** (הוּמוֹר יִשְׂרָאֵלִי), музыка — **музика исраэлит** (מוּזִיקָה יִשְׂרָאֵלִית), кулинария, отношение к природе — **тева** (טֶבַע), пешие маршруты — **швилей Исраэль** (שְׁבִילֵי יִשְׂרָאֵל).
## Вечный вопрос
Декларация независимости — **мегилат hа-ацмаут** (מְגִלַּת הָעַצְמָאוּת, мегилАт hа-ацмаУт) — определяет Израиль как **еврейское и демократическое государство** — **медина йехудит ве-демократит** (מְדִינָה יְהוּדִית וְדֶמוֹקְרָטִית). Напряжение между этими двумя определениями — источник бесконечных дебатов: какой смысл вкладывается в «еврейское»? Религиозный, этнический, культурный? Как это сочетается с правами нееврейских граждан? Эти вопросы остаются открытыми, и именно это делает израильскую идентичность живой, динамичной и незавершённой.', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (47, 'holiday', 'Рош ха-Шана — еврейский Новый год', 'ראש השנה — השנה החדשה', '# Рош ха-Шана — еврейский Новый год (ראש השנה)
**Рош ха-Шана** (ראש השנה, рош hа-шанА) — один из важнейших праздников еврейского календаря. Он празднуется осенью, в первый и второй дни месяца тишрей (תִּשְׁרֵי). Название буквально означает «голова года».
## Традиции и символы
Главный символ — **шофар** (שׁוֹפָר) — рог барана, в который трубят в синагоге. Его звук напоминает о необходимости духовного обновления.
На праздничном столе подают **яблоко с мёдом** — символ сладкого нового года. Говорят: **шана това у-метука** (שנה טובה ומתוקה) — «хорошего и сладкого года». Подают также **гранат** (רימון) — символ множества добрых дел, как зёрен в гранате, и **халу** (חלה) — круглый хлеб, символизирующий цикличность года.
## Поздравления
Самое распространённое поздравление — **шана това** (שנה טובה) — «хорошего года». Принято отправлять открытки и писать пожелания друзьям и родным. В современном Израиле поздравления рассылают через мессенджеры, часто с забавными картинками.
## Рош ха-Шана в Израиле
Это двухдневный выходной. Семьи собираются на праздничный ужин. Многие посещают синагогу. В городах устанавливают столы с мёдом и яблоками для всех желающих. Атмосфера — торжественная, но тёплая и семейная.', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (48, 'holiday', 'Йом Кипур — День Искупления', 'יום כיפור — יום הכיפורים', '# Йом Кипур — День Искупления (יום כיפור)
**Йом Кипур** (יום כיפור, йом кипУр) — самый священный день в еврейском календаре. Наступает через десять дней после Рош ха-Шана.
## Пост и молитва
Это день 25-часового поста — **цом** (צוֹם) — с заката до появления звёзд следующего вечера. Запрещено есть, пить, носить кожаную обувь и работать. Весь день проводят в молитве — **тфила** (תפילה). Центральная молитва — **Кол Нидрей** (כל נדרי) — звучит в начале праздника.
## Израиль в Йом Кипур
Вся страна замирает. Не работает транспорт, закрыты все магазины, прекращается теле- и радиовещание. Шоссе пустеют, и дети выезжают на велосипедах на пустые дороги — это стало отдельной народной традицией.
## Прощение
Перед Йом Кипуром принято просить прощения у тех, кого обидели в течение года. Говорят: **сликха** (סליחה) — «прости». После завершения поста звучит длинный трубный звук шофара — **ткия гдола** (תקיעה גדולה), и все собираются на совместную трапезу.', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (49, 'holiday', 'Суккот — Праздник шалашей', 'סוכות — חג הסוכות', '# Суккот — Праздник шалашей (סוכות)
**Суккот** (סוכות, сукОт) празднуется через пять дней после Йом Кипура и длится семь дней. Это один из трёх **праздников паломничества** (שלוש רגלים, шалОш регалИм).
## Сукка — временный шалаш
Главная традиция — строительство **сукки** (סוכה) — временного шалаша с крышей из растений. В ней едят, а некоторые и спят в течение праздника. Через крышу должны быть видны звёзды. Сукку украшают фруктами, рисунками и гирляндами.
## Четыре вида растений
Во время праздника совершают обряд с **арбаат hа-миним** (ארבעת המינים) — четырьмя видами растений: **лулав** (לולב) — пальмовая ветвь, **этрог** (אתרוג) — цитрон, **hадас** (הדס) — мирт и **арава** (ערבה) — ива.
## Суккот в Израиле
На балконах и во дворах по всей стране вырастают сукки. В школах — каникулы. Погода ещё тёплая, и семьи проводят время на природе. Это весёлый праздник — **зман симхатЕну** (זמן שמחתנו) — «время нашей радости».', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (50, 'holiday', 'Ханука — Праздник огней', 'חנוכה — חג האורות', '# Ханука — Праздник огней (חנוכה)
**Ханука** (חנוכה, ханукА) — восьмидневный праздник, отмечаемый зимой (кислев, כסלו). Он посвящён чуду: маленький кувшин масла горел восемь дней в Храме.
## Зажигание свечей
Каждый вечер зажигают свечи в **ханукии** (חנוכיה) — особом девятисвечнике. В первый вечер — одну свечу, во второй — две, и так до восьми. Девятая свеча — **шамаш** (שמש) — «служебная», от неё зажигают остальные. Ханукию ставят у окна, чтобы все видели.
## Традиционная еда
Едят блюда, приготовленные на масле: **суфганиёт** (סופגניות) — пончики с джемом, и **левивот** (לביבות) — картофельные оладьи (латкес). В магазинах появляются сотни видов суфганиёт с разными начинками: шоколад, крем, халва.
## Ханука для детей
Дети играют в **свивон** (סביבון) — волчок с четырьмя буквами: נ, ג, ה, פ — начальные буквы фразы «чудо великое произошло здесь». Принято дарить **дмей ханука** (דמי חנוכה) — ханукальные деньги.', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (51, 'holiday', 'Пурим — праздник карнавала и радости', 'פורים — חג התחפושות', '# Пурим — праздник карнавала и радости (פורים)
**Пурим** (פורים, пурИм) — один из самых весёлых еврейских праздников. Он отмечается в месяце адар (אדר) и посвящён спасению еврейского народа от злодея Амана, как описано в **Мегилат Эстер** (מגילת אסתר) — Свитке Эстер.
## Традиции Пурима
- **Чтение Мегилы** (קריאת המגילה) — в синагоге читают Свиток Эстер. При упоминании имени Амана все шумят и топают, чтобы его заглушить.
- **Мишлоах манот** (משלוח מנות) — отправка подарков с едой друзьям.
- **Матанот ла-эвйоним** (מתנות לאביונים) — подарки бедным.
- **Маскарад** — дети и взрослые наряжаются в костюмы.
## Пурим в Израиле
Это настоящий карнавал. На улицах проходят парады — **адлояда** (עדלאידע) — особенно яркий в Холоне. Школы и детсады устраивают утренники. Традиционное печенье — **озней Аман** (אוזני המן) — «уши Амана» — треугольные пирожки с маком, шоколадом или финиками.', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (52, 'holiday', 'Песах — праздник свободы', 'פסח — חג החירות', '# Песах — праздник свободы (פסח)
**Песах** (פסח, пЕсах) — весенний праздник, длится семь дней. Он посвящён освобождению еврейского народа из египетского рабства — **ициат Мицраим** (יציאת מצרים).
## Подготовка к Песаху
Перед праздником проводят генеральную уборку, удаляя из дома весь **хамец** (חמץ) — квасное (хлеб, макароны, печенье). Вместо хлеба едят **мацу** (מצה) — пресные лепёшки, напоминающие о том, что евреи покидали Египет в спешке, не успев заквасить тесто.
## Седер Песах
Главное событие — **сЕдер** (סדר) — праздничный ужин в первый вечер. Читают **Агаду** (הגדה) — рассказ об Исходе. На столе стоит **кеара** (קערה) — блюдо с символическими продуктами: горькие травы (марор, מרור), яйцо, яблочная смесь (харосет, חרוסת) и другие. Пьют четыре бокала вина.
## Песах в Израиле
Магазины убирают с полок всё квасное. Улицы заполняются ароматом барбекю — **аль hа-эш** (על האש). Семьи собираются на Седер, дети ищут спрятанный кусочек мацы — **афикоман** (אפיקומן).', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (53, 'holiday', 'Шавуот — праздник дарования Торы', 'שבועות — חג מתן תורה', '# Шавуот — праздник дарования Торы (שבועות)
**Шавуот** (שבועות, шавуОт) празднуется через семь недель после Песаха. Название означает «недели». Праздник связан с дарованием Торы на горе Синай и с началом сбора урожая.
## Традиции
В ночь Шавуота принято учить Тору до утра — **тикун лейль Шавуот** (תיקון ליל שבועות). Читают Книгу Рут (מגילת רות). Едят молочные блюда: чизкейки, блинчики с творогом — **блинцес**. По одной из версий, это связано с тем, что евреи, получив законы кашрута, не могли сразу приготовить мясо.
## Шавуот в Израиле
В кибуцах это праздник первых плодов — **хаг hа-бикурим** (חג הביכורים). Устраивают красочные процессии с корзинами фруктов и овощей. Дети надевают белые одежды и венки из цветов. В городах проходят ночные учебные марафоны в синагогах и культурных центрах.', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (54, 'holiday', 'Ту би-Шват — Новый год деревьев', 'ט"ו בשבט — ראש השנה לאילנות', '# Ту би-Шват — Новый год деревьев (ט"ו בשבט)
**Ту би-Шват** (ט"ו בשבט, ту би-шват) отмечается 15 числа месяца шват. Это «Новый год деревьев» — **рош hа-шана ла-иланот** (ראש השנה לאילנות).
## Традиции
В этот день принято **сажать деревья** — **линтОа эцим** (לנטוע עצים). Школьники выезжают на специальные мероприятия по посадке в лесах **Керен Каемет** (קרן קיימת) — Еврейского национального фонда. Едят **сухофрукты** и плоды Земли Израиля: финики (תמרים), инжир (תאנים), гранаты (רימונים), оливки (זיתים).
## Ту би-Шват сегодня
В современном Израиле праздник приобрёл экологическое значение. Проводятся акции по озеленению, экологические уроки в школах. В кафе предлагают специальное меню из семи видов растений, которыми славится Земля Израиля — **шивъат hа-миним** (שבעת המינים): пшеница, ячмень, виноград, инжир, гранат, олива и финик.', 1);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (55, 'custom', 'Шаббат — еженедельный островок покоя', 'שבת — אי של מנוחה', '# Шаббат — еженедельный островок покоя (שבת)
**Шаббат** (שבת, шабАт) — седьмой день недели, день отдыха. Он начинается в пятницу вечером с заходом солнца и завершается в субботу вечером.
## Встреча Шаббата
Зажигают **нерот Шаббат** (נרות שבת) — субботние свечи. Произносят **кидуш** (קידוש) — благословение над вином. Отламывают кусочек **халы** (חלה) — плетёного хлеба. Семья собирается на праздничный ужин — **арухат Шаббат** (ארוחת שבת).
## Шаббат в разных семьях
Религиозные семьи строго соблюдают запреты: не пользуются электричеством, не водят машину, не работают. Светские семьи часто ограничиваются совместным ужином. В Тель-Авиве кафе и бары работают, пляжи полны людей.
## «Шаббат шалом»
Перед Шаббатом все говорят друг другу **шабат шалом** (שבת שלום) — «мирного Шаббата». Общественный транспорт в большинстве городов не работает, хотя эта тема — предмет постоянных дискуссий.', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (56, 'custom', 'Израильская уличная еда — от фалафеля до шакшуки', 'אוכל רחוב ישראלי', '# Израильская уличная еда (אוכל רחוב ישראלי)
Израильская уличная еда — это смесь ближневосточных, средиземноморских и восточноевропейских влияний. Еда здесь — часть национальной идентичности.
## Фалафель и хумус
**Фалафель** (פלאפל) — жареные шарики из нута в пите — неофициальное национальное блюдо. **Хумус** (חומוס) подают в специальных **хумусиёт** (חומוסיות). Едят макая питу или хлеб.
## Шаварма и сабих
**Шаварма** (שווארמה) — мясо на вертеле. **Сабих** (סביח) — иракское блюдо: пита с жареным баклажаном, яйцом и тхиной.
## Шакшука
**Шакшука** (שקשוקה) — яйца, тушённые в томатном соусе со специями. Подают на завтрак прямо на сковороде с хлебом.
## Израильский завтрак
Знаменитый **арухат бокер** (ארוחת בוקר): салат из свежих овощей, яйца, сыры, оливки, хумус и свежий хлеб. Такой завтрак подают в каждом отеле и кафе.', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (57, 'custom', 'Армейская служба — ЦАХАЛ в жизни израильтян', 'שירות צבאי — צה"ל בחיי הישראלים', '# Армейская служба — ЦАХАЛ (צה"ל)
В Израиле действует **всеобщая воинская обязанность** — **гиюс хова** (גיוס חובה). Юноши служат 32 месяца, девушки — 24 месяца.
## Призыв
В 18 лет молодые люди получают **цав ришон** (צו ראשון) — первую повестку. Проходят медицинские и психологические проверки. Распределяют по подразделениям.
## Элитные подразделения
Самые престижные: **Саерет Маткаль** (סיירת מטכ"ל), **Голани** (גולני), подразделение разведки **8200** (יחידה 8200). Выпускники 8200 часто основывают стартапы.
## Армия как плавильный котёл
ЦАХАЛ называют **кур hа-итух** (כור ההיתוך) — плавильный котёл. Здесь встречаются люди из разных общин и стран. Армейская дружба часто длится всю жизнь.', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (58, 'custom', 'Кибуц — коммунальная жизнь по-израильски', 'הקיבוץ — חיים קהילתיים', '# Кибуц — коммунальная жизнь (הקיבוץ)
**Кибуц** (קיבוץ) — уникальная форма коллективного поселения. Первый кибуц — **Дгания** (דגניה) — основан в 1910 году.
## Классический кибуц
В классическом кибуце всё принадлежало общине: дома, одежда, еда. Питались в **хадар охель** (חדר אוכל) — общей столовой. Решения принимали на общем собрании — **асефа клалит** (אסיפה כללית).
## Современный кибуц
Сегодня большинство кибуцев прошли через **hафрата** (הפרטה) — приватизацию. Ввели зарплаты, разрешили частное жильё. Около 270 кибуцев в стране. Многие привлекают молодые семьи безопасностью и зеленью.', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (59, 'custom', 'Мошав — сельский кооператив Израиля', 'המושב — קואופרטיב כפרי', '# Мошав — сельский кооператив (המושב)
**Мошав** (מושב, мошАв) — форма сельского поселения, менее коллективная, чем кибуц. Каждая семья имеет собственный участок земли и хозяйство.
## Отличие от кибуца
В кибуце всё общее, в мошаве — индивидуальные хозяйства при совместном сбыте продукции. Первый мошав — **Нахалаль** (נהלל) — основан в 1921 году в Изреельской долине.
## Мошав сегодня
В Израиле около 450 мошавов. Многие превратились в пригородные посёлки, жители которых работают в городах. Сельское хозяйство сочетается с агротуризмом — **тиюр хакла''и** (תיור חקלאי). Мошавы славятся свежими продуктами — **тоцерет hа-арец** (תוצרת הארץ) — «продукция страны».', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (60, 'custom', 'Пляжная культура Израиля', 'תרבות החוף בישראל', '# Пляжная культура Израиля (תרבות החוף)
Израиль — страна с 270 километрами средиземноморского побережья. **Пляж** — **хоф** (חוף) — важнейшая часть израильской культуры.
## Пляж как образ жизни
Для тель-авивцев пляж — это продолжение гостиной. Здесь занимаются спортом — **мАтконт** (מטקות) — пляжные ракетки — национальная игра. Играют в волейбол, бегают вдоль берега, занимаются йогой на закате.
## Главные пляжи
**Гордон-бич** (חוף גורדון) и **Фришман** (חוף פרישמן) в Тель-Авиве, **Дадо** (חוף דדו) в Хайфе, **Бат-Ям** и **Нетания** — популярные направления. На Красном море в Эйлате — коралловые рифы.
## Закат на пляже
Смотреть закат — **шкиа** (שקיעה) — на море — почти ритуал. Пляжные кафе, живая музыка, семейные пикники — пляж объединяет всех, от студентов до пенсионеров.', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (61, 'custom', 'Кафе-культура Израиля', 'תרבות בתי הקפה', '# Кафе-культура Израиля (תרבות בתי הקפה)
Израиль — страна кофеманов. **Бейт кафе** (בית קפה) — кофейня — это не просто место выпить кофе, а второй дом.
## Кофе по-израильски
**Кафе шахор** (קפה שחור) — чёрный кофе. **Кафе хафух** (קפה הפוך) — «перевёрнутый кофе» — аналог латте, самый популярный. **Кафе турки** (קפה טורקי) — кофе по-турецки, с кардамоном — **hэль** (הל).
## Кафе как пространство
В кафе работают за ноутбуком, проводят деловые встречи, читают газеты, встречаются с друзьями. Многие кафе открыты допоздна. В Тель-Авиве и Иерусалиме — сотни кофеен на любой вкус.
## Традиция «арухат бокер»
Израильский завтрак в кафе — целое событие: щедрая порция с салатом, яйцами, сырами, хумусом и свежим хлебом. «Поехать на арухат бокер» — популярный формат выходного дня.', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (62, 'custom', 'Общественный транспорт в Израиле', 'תחבורה ציבורית בישראל', '# Общественный транспорт (תחבורה ציבורית)
Транспортная система Израиля развивается быстрыми темпами, хотя всё ещё сильно зависит от автомобилей.
## Автобусы
Главный перевозчик — **Эгед** (אגד) и **Дан** (דן). Автобусы ходят по всей стране. Оплата — картой **Рав-Кав** (רב-קו) — универсальным проездным.
## Поезда
**Ракевет Исраэль** (רכבת ישראל) — национальная железная дорога. Линии соединяют Тель-Авив, Хайфу, Беэр-Шеву и Иерусалим. Скоростной поезд Тель-Авив — Иерусалим идёт всего 30 минут.
## Лёгкий трамвай
В Иерусалиме работает **ракевет кала** (רכבת קלה) — лёгкий трамвай, соединяющий запад и восток города. В Тель-Авиве строят метро — **метро** (מטרו).
## Шаббат
Главная особенность: общественный транспорт не работает в Шаббат в большинстве городов. Это создаёт трудности для тех, у кого нет машины.', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (63, 'custom', 'Система здравоохранения — купот холим', 'מערכת הבריאות — קופות חולים', '# Система здравоохранения (מערכת הבריאות)
Израильская медицина — одна из лучших в мире. Каждый гражданин обязан состоять в одной из четырёх **купот холим** (קופות חולים) — больничных касс.
## Четыре больничные кассы
**Клалит** (כללית), **Маккаби** (מכבי), **Меухедет** (מאוחדת) и **Леумит** (לאומית). Из зарплаты удерживают **мас бриют** (מס בריאות) — налог на здоровье.
## Как устроено
Первый контакт — **рофе мишпаха** (רופא משפחה) — семейный врач в поликлинике — **мирпаа** (מרפאה). К специалисту нужно направление. Запись через приложение.
## Скорая помощь
**Маген Давид Адом** (מגן דוד אדום) — израильский Красный Крест. Номер вызова — 101. Израиль лидирует по продолжительности жизни (более 83 лет).', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (64, 'custom', 'Система образования в Израиле — от ган до университета', 'מערכת החינוך — מגן ועד אוניברסיטה', '# Система образования (מערכת החינוך)
Образование в Израиле обязательно и бесплатно с 3 до 18 лет.
## Структура
Три ступени: **бейт сефер йесоди** (בית ספר יסודי) — начальная школа (1–6), **хативат бейнаим** (חטיבת ביניים) — средняя (7–9), **тихон** (תיכון) — старшая (10–12).
## Багрут
Главная цель — экзамен на **багрут** (בגרות) — аттестат зрелости. Предметы сдают на разных уровнях — **йехидот** (יחידות). Пять единиц по математике — престижно.
## Высшее образование
Восемь университетов: **Технион** (טכניון), **Еврейский университет** (האוניברסיטה העברית), **Тель-Авивский** (אוניברסיטת תל אביב) и другие. Студенты поступают после армии, обычно в 21–23 года.
## Молодёжные движения
**Тнуот ноар** (תנועות נוער) — скауты, рабочая молодёжь — важная часть неформального образования.', 2);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (65, 'society', 'Израильская музыка — от песен первопоселенцев до мирового попа', 'מוזיקה ישראלית — משירי הארץ ועד הפופ העולמי', '# Израильская музыка (מוזיקה ישראלית)
Израильская музыка — **музика исраэлит** (מוזיקה ישראלית) — отражает многообразие общества. От песен Земли Израиля до современного попа.
## Ширей Эрец Исраэль
**Ширей Эрец Исраэль** (שירי ארץ ישראל) — «песни Земли Израиля» — классический канон. Наоми Шемер, Эхуд Манор — поэты, чьи песни знает каждый. «Ерушалаим шель заhав» — «Золотой Иерусалим» — неофициальный гимн.
## Мизрахит
**Музыка мизрахит** (מוזיקה מזרחית) — восточные мелодии с арабскими и турецкими влияниями. Зоар Аргов — «hа-мелех» (המלך, «король»). Сегодня это мейнстрим: Омер Адам, Эден Бен Зекен.
## Современная сцена
Израильские артисты выходят на мировую арену. Нетта выиграла Евровидение в 2018. Развиваются рэп, электроника, инди. Фестиваль **Инди-Сити** и **Тамар-фестиваль** привлекают тысячи.', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (66, 'society', 'Израильское кино — от пропаганды до «Оскара»', 'קולנוע ישראלי — מפרופגנדה ועד לאוסקר', '# Израильское кино (קולנוע ישראלי)
Израильский кинематограф прошёл путь от идеологических фильмов до номинантов и лауреатов международных фестивалей.
## Ранний период
В первые десятилетия снимали фильмы о героизме и строительстве государства. **«Бурекас»** (בורקס) — жанр народных комедий 1960–70-х, высмеивающих межобщинные стереотипы.
## Новая волна
С 1990-х — расцвет авторского кино. **Амос Гитай** (עמוס גיטאי), **Шмуэль Маоз** — «Ливан» (לבנון) — «Золотой лев» Венеции. **«Вальс с Баширом»** (ואלס עם באשיר) — анимационный документальный фильм о Ливанской войне.
## Современное кино
Израильские фильмы регулярно попадают на фестивали в Канне, Берлине, Венеции. Телесериал **«Фауда»** (פאודה) стал международным хитом. **«Штисель»** (שטיסל) открыл миру мир ультраортодоксов.', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (67, 'society', 'Стартапы и хайтек — нация инноваций', 'סטארט-אפים והייטק — אומת החדשנות', '# Стартапы и хайтек (סטארט-אפים והייטק)
Израиль — **умат hа-стартап** (אומת הסטארט-אפ) — занимает первое место по числу стартапов на душу населения.
## Экосистема
Центр — Тель-Авив и Герцлия. Ключевые секторы: **кибербезопасность** (סייבר), **финтех** (פינטק), **медтех** (מדטק), **агритех** (אגריטק). Капельное орошение — израильское изобретение.
## Факторы успеха
- Выпускники подразделения **8200** — основа кибер-индустрии
- **Хуцпа** (חוצפה) — готовность бросать вызов авторитетам
- Толерантность к провалу
- Мультикультурность инженерных команд
## Хайтек и общество
Хайтек — 15% ВВП, 50% экспорта. Зарплаты в 2,5 раза выше средних. Создаёт разрыв между «нацией стартапов» и остальной страной. Правительство поддерживает инновации через **Рашут hа-хидуш** (רשות החדשנות).', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (68, 'society', 'Алия — волны иммиграции в Израиль', 'עלייה — גלי ההגירה לישראל', '# Алия — волны иммиграции (עלייה)
**Алия** (עלייה) — буквально «восхождение» — репатриация евреев в Землю Израиля.
## Исторические волны
Пять основных волн до 1948 года: из Российской империи, из Польши, бегство от нацизма. После создания государства — массовая алия из арабских стран, из Эфиопии и из СССР.
## Большая русская алия
В 1990-х около миллиона человек прибыли из СССР и СНГ. Привезли учёных, врачей, инженеров, музыкантов. Русский стал третьим языком страны.
## Процесс абсорбции
Новые репатрианты — **олим хадашим** (עולים חדשים) — получают **саль клита** (סל קליטה) — корзину абсорбции. Учат иврит в **ульпане** (אולפן). Закон о возвращении — **Хок hа-Швут** (חוק השבות) — даёт каждому еврею право на репатриацию.', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (69, 'society', 'Друзская община в Израиле', 'העדה הדרוזית בישראל', '# Друзская община (העדה הדרוזית)
**Друзы** (דרוזים, друзИм) — этно-религиозная община, около 150 тысяч человек в Израиле. Живут в основном на горе Кармель и Голанских высотах.
## Религия
Друзская религия — ответвление ислама, но со своими особенностями. Вера основана на единобожии — **таухид** (תאוחיד). Религиозные практики тайные, доступны только **укаль** (עוקאל) — посвящённым.
## Служба в армии
Друзы — единственное нееврейское меньшинство с обязательной военной службой. Считается, что **брит дам** (ברית דם) — «кровный союз» — связывает друзов с еврейским государством.
## Культура и кухня
Друзские деревни — **Далият аль-Кармель** (דאלית אל-כרמל), **Исфия** (עספיא) — популярны среди туристов. Друзская кухня: **мансаф** — баранина с рисом, **кнафе** — десерт с сыром.', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (70, 'society', 'Бедуины Негева — между традицией и современностью', 'הבדואים בנגב — בין מסורת למודרניזציה', '# Бедуины Негева (הבדואים בנגב)
**Бедуины** (בדואים, бедуИм) — около 280 тысяч человек в Негеве. Крупнейшая община кочевников на Ближнем Востоке, переживающая переход к оседлому образу жизни.
## Традиционная культура
Бедуинское гостеприимство — **hахнасат орхим** (הכנסת אורחים) — легендарно. Кофе — **каhва** (קהווה) — готовят в присутствии гостя как знак уважения. Традиционное жилище — **охель** (אוהל) — шатёр.
## Современные вызовы
Переход из кочевого в городской быт создаёт трудности. Молодёжь стремится к образованию и работе в городе. Бедуинские женщины всё чаще получают высшее образование.
## Город Рахат
**Рахат** (רהט) — крупнейший бедуинский город, около 70 тысяч жителей. Бедуины также служат в ЦАХАЛе, особенно в следопытских подразделениях — **гадсарим** (גדסרים).', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (71, 'society', 'Эфиопские евреи — Бейта Исраэль', 'יהודי אתיופיה — ביתא ישראל', '# Эфиопские евреи — Бейта Исраэль (ביתא ישראל)
**Бейта Исраэль** (ביתא ישראל) — община эфиопских евреев, мечтавшая о возвращении в Сион тысячи лет.
## Операции по спасению
**Операция «Моше»** (מבצע משה, 1984) и **«Шломо»** (מבצע שלמה, 1991) — тайные операции по переброске эфиопских евреев в Израиль. За 36 часов в рамках «Шломо» было перевезено 14 000 человек.
## Вклад в культуру
Эфиопская община привнесла уникальные традиции: праздник **Сигд** (סיגד) — день паломничества, ставший государственным праздником. Традиционные священники — **кесим** (כסים). Музыканты вроде **Эсте Радар** (אסתר רדא) стали звёздами.
## Вызовы интеграции
Община (около 160 тысяч) сталкивается с трудностями: разрыв в образовании, социальная дискриминация. Протесты 2015 года привлекли внимание общества. Молодое поколение активно добивается равенства.', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (72, 'society', 'Русскоязычная община Израиля', 'הקהילה דוברת הרוסית בישראל', '# Русскоязычная община (הקהילה דוברת הרוסית)
Около 1,2 миллиона израильтян говорят по-русски. Это крупнейшая русскоязычная диаспора на Ближнем Востоке.
## Большая алия 1990-х
Около миллиона человек прибыли из СССР и СНГ в 1989–2001 годах. Среди них — тысячи учёных, врачей, инженеров, музыкантов. Репатрианты кардинально изменили экономику и культуру Израиля.
## Культурное влияние
Русскоязычные СМИ: газета «Вести» (вЕсти), телеканал «9 канал» (ערוץ 9). Русский театр «Гешер» (גשר, мост) — один из лучших в стране. Классическая музыка обогатилась сотнями профессионалов.
## Идентичность
«Русские» израильтяне — **русим** (רוסים) — сохраняют свою культуру, отмечают 9 мая и Новый год, но интегрированы в израильское общество. Второе поколение полностью двуязычно.', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (73, 'society', 'Спорт в Израиле — от Маккаби до олимпийских медалей', 'ספורט בישראל — ממכבי ועד למדליות אולימפיות', '# Спорт в Израиле (ספורט בישראל)
Спорт в Израиле — это не только физкультура, но и национальная гордость, и площадка для социальной интеграции.
## Футбол
**Кадурегель** (כדורגל) — самый популярный вид спорта. Главные клубы: **Маккаби Тель-Авив** (מכבי תל אביב), **Хапоэль Беэр-Шева** (הפועל באר שבע), **Бейтар Иерусалим** (בית"ר ירושלים). Национальная лига — **Лигат hа-Аль** (ליגת העל).
## Баскетбол
**Кадурсаль** (כדורסל) — второй по популярности. **Маккаби Тель-Авив** — шестикратный чемпион Евролиги. Баскетбольный клуб — гордость страны.
## Олимпийские достижения
Израильские спортсмены завоёвывают медали в дзюдо, парусном спорте, спортивной гимнастике. **Маккабиада** (המכביה) — «еврейская Олимпиада» — проводится в Израиле раз в четыре года.
## Мацконт
**Мацконт** (מטקות) — пляжные ракетки — неофициальный национальный спорт. Звук ударов мяча — саундтрек каждого израильского пляжа.', 3);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (74, 'history', 'Основание Государства Израиль — 1948', 'הקמת מדינת ישראל — 1948', '# Основание Государства Израиль (הקמת מדינת ישראל)
14 мая 1948 года **Давид Бен-Гурион** (דוד בן-גוריון) зачитал **Декларацию независимости** — **мегилат hа-ацмаут** (מגילת העצמאות) — в Тель-Авивском музее. Этот момент стал кульминацией сионистского движения, начавшегося за полвека до того.
## Предыстория
Британский мандат (1920–1948) переживал нарастающий кризис. Конфликт между еврейским и арабским населением, послевоенная иммиграция выживших в Холокосте, давление международного сообщества. В ноябре 1947 года ООН приняла **резолюцию 181** — план раздела Палестины на еврейское и арабское государства. Евреи приняли план, арабы отвергли.
## Провозглашение
Бен-Гурион провозгласил: «Мы объявляем о создании еврейского государства в Эрец-Исраэль — Государства Израиль». На следующий день армии пяти арабских стран вторглись в новорождённое государство. Началась **Война за независимость** — **Милхемет hа-Ацмаут** (מלחמת העצמאות).
## Первые годы
Война закончилась перемирием в 1949 году. Сотни тысяч палестинских арабов стали беженцами — **Накба** (נכבה, катастрофа). Одновременно в Израиль хлынули массы еврейских иммигрантов из арабских стран и Европы. Государство строилось в условиях жесточайшей экономии — **цена** (צנע, цнА) — режим строгого нормирования продуктов. Несмотря на трудности, были созданы основные государственные институты: **Кнессет** (הכנסת), армия, система образования и судебная система.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (75, 'history', 'Шестидневная война — 1967', 'מלחמת ששת הימים — 1967', '# Шестидневная война (מלחמת ששת הימים)
В июне 1967 года Израиль вёл войну на три фронта одновременно — и победил за шесть дней. Эта война радикально изменила карту Ближнего Востока и определила основные параметры конфликта на десятилетия.
## Предпосылки
Президент Египта Насер закрыл Тиранский пролив для израильского судоходства, потребовал вывода сил ООН с Синая и заключил военный пакт с Иорданией и Сирией. Израиль оказался в окружении.
## Ход войны
5 июня ВВС Израиля нанесли упреждающий удар, уничтожив египетские ВВС на земле. За шесть дней были заняты Синайский полуостров, Газа, Западный берег Иордана, Восточный Иерусалим и Голанские высоты.
## Объединение Иерусалима
Десантники прорвались к **Котелю** (הכותל) — Стене Плача. Генерал **Мота Гур** (מוטה גור) произнёс историческую фразу: «hар hа-Байт бе-ядЕну» (הר הבית בידינו) — «Храмовая гора в наших руках».
## Последствия
Победа принесла эйфорию, но и новые проблемы: оккупация территорий с более чем миллионом палестинских арабов, начало поселенческого движения, мировое осуждение. Эти последствия определяют израильскую реальность по сей день.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (76, 'history', 'Война Судного дня — 1973', 'מלחמת יום הכיפורים — 1973', '# Война Судного дня (מלחמת יום הכיפורים)
6 октября 1973 года, в самый священный день еврейского календаря — **Йом Кипур** — Египет и Сирия внезапно атаковали Израиль.
## Внезапность
Несмотря на предупреждения разведки, политическое руководство не приняло мер. Египетская армия форсировала Суэцкий канал, сирийские танки вошли на Голанские высоты. Первые дни стали шоком — **мехдаль** (מחדל) — «провал».
## Перелом
Израиль провёл массовую мобилизацию резервистов. На севере остановили сирийское наступление. На юге генерал Ариэль Шарон переправился через Суэцкий канал, окружив египетскую армию.
## Последствия
Война закончилась военной победой, но национальной травмой. Погибли около 2700 солдат. **Комиссия Аграната** (ועדת אגרנט) расследовала провал разведки. Премьер-министр Голда Меир и министр обороны Моше Даян ушли в отставку. Война привела к Кэмп-Дэвидским соглашениям и миру с Египтом в 1979 году.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (77, 'history', 'Соглашения Осло — попытка мира', 'הסכמי אוסלו — ניסיון השלום', '# Соглашения Осло (הסכמי אוסלו)
В сентябре 1993 года на лужайке Белого дома произошло историческое рукопожатие между **Ицхаком Рабином** (יצחק רבין) и **Ясиром Арафатом** (יאסר ערפאת). Были подписаны **Соглашения Осло** — **hескемей Осло** (הסכמי אוסלו).
## Содержание
Израиль признал ООП представителем палестинского народа, ООП признала право Израиля на существование. Создана **Палестинская автономия** — **hа-Рашут hа-Палестинит** (הרשות הפלסטינית). Территории разделены на зоны A, B и C с разной степенью контроля.
## Надежды и крах
Соглашения породили огромные надежды. Рабин, Арафат и Перес получили Нобелевскую премию мира. Но волна терактов и убийство Рабина в 1995 году фанатиком **Игалем Амиром** (יגאל עמיר) подорвали мирный процесс.
## Наследие
Соглашения Осло остаются правовой основой отношений между Израилем и палестинцами, хотя обе стороны обвиняют друг друга в нарушениях. Вопрос «два государства для двух народов» — **штей мединот ли-шней амим** (שתי מדינות לשני עמים) — остаётся центральным в международной повестке.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (78, 'history', 'Эфиопская алия — операции «Моше» и «Шломо»', 'העלייה האתיופית — מבצעי משה ושלמה', '# Эфиопская алия (העלייה האתיופית)
История переселения эфиопских евреев — **Бейта Исраэль** (ביתא ישראל) — одна из самых драматических глав в истории репатриации.
## Операция «Моше» — 1984
Тайная операция по спасению еврейских беженцев из суданских лагерей. Около 8000 человек были переправлены в Израиль. Многие погибли в пути через пустыню. Операция прервалась после утечки информации.
## Операция «Шломо» — 1991
Крупнейшая воздушная эвакуация: за 36 часов 34 самолёта перевезли более 14 000 эфиопских евреев. Борт El Al побил рекорд — 1122 пассажира на одном самолёте (двое родились в полёте).
## Интеграция
Переход из аграрного общества в современное государство стал огромным вызовом. Проблемы: разрыв в образовании, бедность, культурный шок. Но община постепенно интегрируется: растёт число студентов, офицеров, политиков эфиопского происхождения. Праздник **Сигд** стал государственным.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (79, 'history', 'Советская алия — миллион, изменивший страну', 'העלייה מברית המועצות — מיליון ששינה מדינה', '# Советская алия (העלייה מברית המועצות)
Волна иммиграции из Советского Союза и стран СНГ в 1989–2001 годах — крупнейшая в истории Израиля после 1948 года.
## Масштаб
Около миллиона человек — 20% тогдашнего населения страны. Среди них — непропорционально высокая доля людей с высшим образованием: учёные, инженеры, врачи, музыканты, программисты.
## Влияние на экономику
Репатрианты стали одним из двигателей хайтек-бума 1990-х. Они заполнили больницы врачами, оркестры — музыкантами, университеты — учёными. ВВП на душу населения вырос вдвое.
## Культурное влияние
Русскоязычные газеты, телевидение, театры, книжные магазины. Русский стал третьим языком страны. Праздники: Новый год, 9 мая, Масленица — вошли в израильский быт.
## Политическое влияние
Партия **«Исраэль Бейтену»** (ישראל ביתנו) во главе с **Авигдором Либерманом** (אביגדור ליברמן) стала голосом русскоязычных израильтян. Алия из СССР изменила баланс сил в израильской политике.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (80, 'history', 'Эволюция кибуца — от коммуны к пригороду', 'התפתחות הקיבוץ — מקומונה לפרבר', '# Эволюция кибуца (התפתחות הקיבוץ)
Кибуц — **кибуц** (קיבוץ) — прошёл путь от радикальной коммуны до процветающего пригородного посёлка.
## Золотой век (1920–1970)
Кибуцы были авангардом сионизма. Члены кибуца — **хаверим** (חברים) — жили без частной собственности, ели в общей столовой, дети воспитывались в **бейт йеладим** (בית ילדים). Кибуцы давали непропорционально много армейских офицеров и политиков.
## Кризис (1980–1990)
Экономические трудности, долги, смена поколений. Молодёжь уезжала в город. Идеал коллективизма потускнел. Многие кибуцы оказались на грани банкротства.
## Приватизация
Большинство кибуцев прошли через **hафрата** (הפרטה) — приватизацию. Ввели дифференцированные зарплаты, разрешили владеть жильём. Различают **кибуц шитуфи** (קיבוץ שיתופי) — коммунальный, и **кибуц митхадеш** (קיבוץ מתחדש) — обновлённый.
## Кибуц сегодня
270 кибуцев, 170 тысяч жителей. Многие стали привлекательными для молодых семей: безопасность, зелень, общинный дух. Кибуцная промышленность генерирует миллиарды.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (81, 'history', 'Израильские СМИ — от «Коль Исраэль» до TikTok', 'התקשורת הישראלית — מקול ישראל ועד טיקטוק', '# Израильские СМИ (התקשורת הישראלית)
Израильские медиа — одни из самых свободных и конкурентных на Ближнем Востоке.
## Радио и телевидение
**Коль Исраэль** (קול ישראל) — «Голос Израиля» — государственное радио, работавшее с 1936 года. Сегодня его заменила **Кан** (כאן) — общественная корпорация. Коммерческие каналы: **Кешет** (קשת), **Решет** (רשת).
## Пресса
Газеты **Hаарец** (הארץ) — левоцентристская, интеллектуальная. **Едиот Ахронот** (ידיעות אחרונות) — массовая. **Исраэль hа-Йом** (ישראל היום) — бесплатная, правоцентристская.
## Цифровая эпоха
Израильтяне — одни из самых активных пользователей соцсетей. Новостные сайты **Ynet**, **Walla**, **N12** — основные источники информации. Подкасты, YouTube-каналы и TikTok радикально изменили медиаландшафт.
## Свобода прессы
Свобода слова — **хофеш hа-битуй** (חופש הביטוי) — защищена. Однако военная цензура — **цензура цваит** (צנזורה צבאית) — может ограничивать публикации по вопросам безопасности.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (82, 'history', 'Экономика Израиля — от апельсинов к микрочипам', 'הכלכלה הישראלית — מתפוזים למיקרושבבים', '# Экономика Израиля (הכלכלה הישראלית)
Израильская экономика за 75 лет прошла путь от сельскохозяйственной к высокотехнологичной.
## Ранний период
1950-е — режим строгого нормирования (**цена**, צנע). Апельсины **Яффо** (יפו) — главный экспортный продукт. Государственное планирование, сильные профсоюзы — **hистадрут** (ההסתדרות).
## Либерализация
1985 — **программа экономической стабилизации**: обуздание гиперинфляции (450% в год). Приватизация госкомпаний. Открытие рынков.
## Хайтек-бум
1990–2000-е — хайтек стал главным двигателем. ВВП на душу — более 50 000 долларов. Израиль — член ОЭСР с 2010 года. Экспорт высоких технологий — около 50% всего экспорта.
## Вызовы
**Йокер hа-хаим** (יוקר החיים) — дороговизна жизни: жильё, продукты, транспорт. Социальный разрыв между хайтек-сектором и остальной экономикой. Интеграция арабов и ультраортодоксов в рынок труда.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (83, 'history', 'Экология в Израиле — вода, пустыня, инновации', 'אקולוגיה בישראל — מים, מדבר, חדשנות', '# Экология в Израиле (אקולוגיה בישראל)
Израиль — лидер в решении экологических проблем, особенно связанных с водой и пустыней.
## Водный вопрос
Израиль — засушливая страна. Более 60% территории — пустыня **Негев** (נגב). Решение — **hатпала** (התפלה) — опреснение морской воды. Сегодня более 80% питьевой воды получают опреснением. **Капельное орошение** — **тифтуф** (טפטוף) — изобретено в Израиле и используется по всему миру.
## Озеленение
**Керен Каемет** (קרן קיימת) — Еврейский национальный фонд — посадил более 240 миллионов деревьев. Израиль — одна из немногих стран, где лесных площадей стало больше за XX век.
## Возобновляемая энергия
Солнечная энергетика — **энергия солярит** (אנרגיה סולארית) — активно развивается в Негеве. Цель — 30% электроэнергии из возобновляемых источников к 2030 году.
## Переработка
Система **мифаль hа-Паис** (מפעל הפיס) поддерживает экологические проекты. Закон о залоговой стоимости бутылок — **пикадон** (פיקדון) — стимулирует переработку.', 4);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (84, 'culture', 'Израильская литература — голоса нации', 'הספרות הישראלית — קולות האומה', '# Израильская литература (הספרות הישראלית)
Израильская литература — **сифрут исраэлит** (ספרות ישראלית) — за неполное столетие превратилась из идеологического инструмента в многоголосое пространство мирового значения.
## Поколение основателей
**Шмуэль Йосеф Агнон** (ש"י עגנון) — нобелевский лауреат (1966), мастер сплетения талмудического языка и модернизма. **Амос Оз** (עמוס עוז) — самый переводимый израильский автор, голос кибуцного поколения. «Повесть о любви и тьме» — автобиография-шедевр.
## Новая волна
**Давид Гроссман** (דויד גרוסמן) — романист, чьи книги исследуют травму оккупации и личную боль. **Этгар Керет** (אתגר קרת) — мастер короткого рассказа, абсурдист и минималист, символ новой израильской прозы.
## Поэзия
**Иехуда Амихай** (יהודה עמיחי) — величайший поэт, превративший повседневный иврит в инструмент высокой лирики. **Рахель** (רחל) — поэтесса-символ Второй алии. **Далия Равикович** (דליה רביקוביץ'') — голос феминистской поэзии.
## Многоголосие
Сегодня пишут мизрахийские авторы, арабские граждане на иврите, русскоязычные репатрианты. Литература отражает всю сложность израильского общества — это литература вопросов, а не ответов.', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (85, 'culture', 'Израильская философия — мысль на перекрёстке', 'הפילוסופיה הישראלית — מחשבה בצומת', '# Израильская философия (הפילוסופיה הישראלית)
Израильская философия сформировалась на пересечении еврейской традиции мысли, европейского рационализма и уникального опыта строительства нового общества в условиях конфликта.
## Мартин Бубер
**Мартин Бубер** (מרטין בובר) — философ диалога. Его труд «Я и Ты» (אני ואתה) — основа философии межличностных отношений. Бубер выступал за двунациональное государство и диалог с арабами.
## Йешаяху Лейбович
**Лейбович** (ליבוביץ'') — учёный-универсал, «совесть нации». Его острая критика оккупации после 1967 года вызвала бурю. Он разделял религию и государство, предупреждая об опасности обожествления государственности.
## Ависхай Маргалит
**Маргалит** (מרגלית) исследует «достойное общество» — **хевра мехубедет** (חברה מכובדת) — общество, институты которого не унижают людей. Его работы влияют на политическую философию далеко за пределами Израиля.
## Философия сегодня
Израильские философы активно участвуют в этических дебатах: биоэтика, этика войны, права меньшинств. Философские факультеты Еврейского и Тель-Авивского университетов — среди сильнейших.', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (86, 'culture', 'Академия языка иврит — хранители языка', 'האקדמיה ללשון עברית — שומרי השפה', '# Академия языка иврит (האקדמיה ללשון עברית)
**Академия** (האקדמיה ללשון עברית, hа-Академия ле-лашОн иврИт) — высший орган по вопросам ивритского языка, основанный в 1953 году как наследник **Ваад hа-лашон** (ועד הלשון).
## Миссия
Создание новых слов — **хидушей лашон** (חידושי לשון) — для понятий, не существовавших в древнем иврите. «Компьютер» стал **махшев** (מחשב), «электричество» — **хашмаль** (חשמל), «мороженое» — **глида** (גלידה).
## Принципы
Академия предпочитает создавать слова из семитских корней, используя модели словообразования — **мишкалим** (משקלים). Но разговорный язык часто опережает: слова «телефон» (טלפון), «автобус» (אוטובוס), «интернет» (אינטרנט) прижились как есть.
## Диалог с улицей
Академия стоит перед дилеммой: нормативность versus живой язык. Сленг — **сленг** (סלנג) — арабские, английские и русские заимствования постоянно обогащают иврит. Академия публикует рекомендации, но не может запретить слова.', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (87, 'culture', 'Мизрахийская культура — Восток внутри Израиля', 'התרבות המזרחית — המזרח בתוך ישראל', '# Мизрахийская культура (התרבות המזרחית)
**Мизрахим** (מזרחים) — евреи из арабских и мусульманских стран: Марокко, Ирак, Йемен, Иран, Ливия, Тунис, Египет. Около половины еврейского населения Израиля.
## Историческая несправедливость
В первые десятилетия государства мизрахийские иммигранты подвергались дискриминации: их отправляли в **маабарот** (מעברות) — транзитные лагеря, их культура считалась «отсталой». **hа-Пантерим hа-Шхорим** (הפנתרים השחורים) — «Чёрные пантеры» — движение протеста 1970-х.
## Культурный ренессанс
С 1990-х — мизрахийская культура выходит из маргинальности. Музыка мизрахит — мейнстрим. Кухня: **храйме** (חריימה), **кускус** (קוסקוס), **жахнун** (ג''חנון) — на каждом столе. **Мимуна** (מימונה) — марокканский праздник после Песаха — стал общеизраильским.
## Мизрахийский голос
Литература, кино, академия — мизрахийский голос звучит всё громче. Поэты Эрез Битон, Рони Сомек; режиссёры Ави Нешер, Шира Геффен. Мизрахийская идентичность — часть израильской.', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (97, 'society', 'Современная израильская идентичность — кто мы?', 'הזהות הישראלית המודרנית — מי אנחנו?', '# Современная израильская идентичность (הזהות הישראלית המודרנית)
Вопрос **зеhут** (זהות) — идентичности — находится в эпицентре израильского самосознания. Монолитный образ «сабры» уступил место многогранной мозаике идентичностей.
## От «нового еврея» к мозаике
Сионизм стремился создать **«адам хадаш»** (אדם חדש) — «нового человека», противоположность «галутному еврею». Образ **цабар** (צבר) — колючего снаружи, сладкого внутри — доминировал десятилетиями, но оказался исключающим.
## Оси идентичности
Современный израильтянин определяет себя по множеству осей: религиозность (хилони — хареди), этничность (ашкенази — мизрахи — эфиопский — русский), отношение к конфликту (ямин — смоль), отношение к глобализации.
## Исраэлиют
Понятие **исраэлиЮт** (ישראליות) — «израильскость» — попытка найти общее: армейский опыт, юмор, кухня, отношение к природе, прямолинейность, импровизация.
## Вечная дилемма
«Еврейское и демократическое государство» — **медина йехудит ве-демократит** (מדינה יהודית ודמוקרטית) — формула из Декларации независимости. Как сочетаются «еврейское» и «демократическое»? Этот вопрос остаётся открытым, что делает идентичность динамичной и незавершённой.', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (88, 'culture', 'Ашкеназская культура — европейские корни Израиля', 'התרבות האשכנזית — שורשים אירופיים', '# Ашкеназская культура (התרבות האשכנזית)
**Ашкеназим** (אשכנזים) — евреи из Центральной и Восточной Европы. Они основали сионистское движение и доминировали в формировании государственных институтов.
## Идишская основа
Язык **идиш** (אידיש) — тысячелетняя культура ашкеназских евреев. Литература: Шолом-Алейхем, Башевис-Зингер. В Израиле идиш долго вытеснялся в пользу иврита, но сегодня переживает культурное возрождение.
## Кухня
Гефилте фиш (рыба фаршированная), куриный бульон с мацовыми клёцками — **кнейдлах** (קניידלך), форшмак, штрудель. Ашкеназская кухня стала частью израильского быта.
## Культурное наследие
Европейская классическая музыка, академическая традиция, литературный иврит — всё это привнесли ашкеназские иммигранты. Израильская Филармония — **hа-Тизморет hа-Филhармонит** (התזמורת הפילהרמונית) — основана в 1936 году.', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (89, 'culture', 'Светские и религиозные — вечный израильский диалог', 'חילונים ודתיים — הדיאלוג הישראלי הנצחי', '# Светские и религиозные (חילונים ודתיים)
Напряжение между **хилоним** (חילונים) — светскими и **датиим** (דתיים) — религиозными — одна из определяющих осей израильского общества.
## Спектр религиозности
Не бинарное деление, а спектр: **хилони** (חילוני) — светский, **масорти** (מסורתי) — традиционный, **дати** (דתי) — религиозный, **хареди** (חרדי) — ультраортодоксальный. Около 45% — хилоним, 25% — масортим, 15% — датиим, 12% — харедим.
## Ключевые вопросы
**Транспорт в Шаббат** — работает ли общественный транспорт? **Гражданский брак** — его нет, браки только через раввинат. **Призыв харедим** — ультраортодоксы освобождены от армии. **Кашрут** — государственная сертификация.
## Статус-кво
Соглашение 1947 года между Бен-Гурионом и лидерами ультраортодоксов определило «статус-кво» в отношениях религии и государства. Этот баланс постоянно пересматривается.
## Мосты
Несмотря на трения, существуют инициативы диалога. Совместные программы, общие проекты, армейская служба объединяют людей из разных секторов.', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (90, 'culture', 'Современное искусство Израиля', 'האמנות המודרנית בישראל', '# Современное искусство Израиля (האמנות המודרנית)
Израильское искусство — **оманут исраэлит** (אומנות ישראלית) — развивается в уникальном контексте: между Востоком и Западом, войной и повседневностью.
## Музеи
**Музей Израиля** (מוזיאון ישראל) в Иерусалиме — крупнейший: Свитки Мёртвого моря, археология, современное искусство. **Тель-Авивский музей** (מוזיאון תל אביב) — центр современного искусства. **Музей Эрец-Исраэль** — история и культура.
## Художники
**Нахум Гутман** (נחום גוטמן) — художник раннего Тель-Авива. **Рафи Лави** (רפי לביא) — основатель концептуального искусства. **Михаль Ровнер** (מיכל רובנר) — видеоарт мирового уровня. **Сигалит Ландау** (סיגלית לנדאו) — инсталляции в Мёртвом море.
## Арт-сцена
Тель-Авив — центр современного искусства. Галереи на улице **Гордон** и в **Яффо**. Стрит-арт в Флорентине. Ежегодная неделя искусства — **Шавуа hа-оманут** (שבוע האומנות) — привлекает тысячи.', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (91, 'culture', 'Израильский театр — от «Хабимы» до фринджа', 'התיאטרון הישראלי — מהבימה ועד הפרינג''', '# Израильский театр (התיאטרון הישראלי)
Театральная культура Израиля — одна из самых живых и насыщенных в мире по числу зрителей на душу населения.
## Хабима
**Хабима** (הבימה) — национальный театр, основанный в Москве в 1917 году. Переехал в Тель-Авив в 1931. Его здание на площади **Кикар Хабима** (כיכר הבימה) — культурный символ.
## Основные театры
**Камери** (הקאמרי) — Тель-Авивский городской театр, ставящий современную драматургию. **Бейт Лесин** (בית לסין), **Гешер** (גשר) — театр, основанный русскоязычными репатриантами. **Хан** (חאן) в Иерусалиме.
## Фриндж и альтернатива
**Аккофест** (עכו-פסט) — фестиваль альтернативного театра в Акко. **Тмуна** (תמונה) — маленький авангардный театр. Фриндж-фестивали в Тель-Авиве и Беэр-Шеве.
## Драматургия
**Ханох Левин** (חנוך לוין) — величайший израильский драматург, мастер сатиры и абсурда. **Йехошуа Соболь** (יהושע סובול) — автор «Гетто». Современная драматургия исследует идентичность, конфликт и повседневность.', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (92, 'culture', 'Академическая жизнь в Израиле', 'החיים האקדמיים בישראל', '# Академическая жизнь (החיים האקדמיים)
Израиль — мировой лидер по доле учёных на душу населения. Академия — **академия** (אקדמיה) — играет ключевую роль.
## Университеты
Восемь исследовательских университетов: **Технион** (טכניון) — технологии, **Вейцман** (מכון ויצמן) — точные науки, **Еврейский университет** (האוניברסיטה העברית) — гуманитарные и естественные науки. Каждый имеет свою специализацию.
## Нобелевские лауреаты
Израиль дал 13 нобелевских лауреатов — поразительное число для страны с населением менее 10 миллионов. Химия, экономика, литература — лауреаты работают в самых разных областях.
## Публикации и исследования
Израильские учёные публикуются в ведущих журналах мира. Страна занимает первое место по числу научных публикаций на душу населения. Связь академии с хайтеком — двигатель инноваций.
## Студенческая жизнь
Студенты поступают после армии, в 21–23 года — зрелые и мотивированные. **Агудат hа-студентим** (אגודת הסטודנטים) — студенческие ассоциации — активны в общественной жизни.', 5);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (93, 'history', 'История правовой системы Израиля — от османского права к Основным законам', 'תולדות מערכת המשפט — מהמשפט העות''מאני לחוקי היסוד', '# История правовой системы Израиля (תולדות מערכת המשפט)
Израильская правовая система — уникальный гибрид, вобравший элементы османского, британского, еврейского и международного права.
## Османское наследие
До 1917 года Палестина находилась под османским владычеством. Земельное право — **мекаркеин** (מקרקעין) — до сих пор несёт следы османских категорий: **мири** (государственная земля), **мульк** (частная), **маукуф** (вакуфная). Многие земельные споры уходят корнями в этот период.
## Британский мандат
Британцы (1920–1948) привнесли систему **коммон ло** — прецедентного права. Институт прецедента — **тикдим мишпати** (תקדים משפטי) — остаётся основой судопроизводства. Адвокатура, процессуальные нормы, система апелляций — британское наследие.
## Основные законы
У Израиля нет единой конституции. Вместо неё — **хуке йесод** (חוקי יסוד) — Основные законы, принимаемые постепенно. В 1992 году приняты ключевые: «О достоинстве и свободе человека» и «О свободе занятий». Председатель Верховного суда **Аарон Барак** провёл «конституционную революцию» — утвердил судебный контроль над законодательством.
## БАГАЦ
**БАГАЦ** (בג"ץ) — Высший суд справедливости — уникальный институт: любой гражданин может обратиться напрямую по вопросам нарушения основных прав. Это делает судебную систему одной из самых доступных в мире, но и предметом политических дебатов о границах судебной власти.', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (94, 'history', 'Эволюция политической системы — от Бен-Гуриона до коалиционного хаоса', 'התפתחות המערכת הפוליטית — מבן-גוריון ועד כאוס קואליציוני', '# Эволюция политической системы (התפתחות המערכת הפוליטית)
Израильская политика прошла путь от доминирования одной партии к фрагментированной многопартийности.
## Эпоха Мапай (1948–1977)
**Мапай** (מפא"י) — Рабочая партия — доминировала три десятилетия. Бен-Гурион, Шарет, Эшколь, Голда Меир — все из одной партии. Государство строилось по социал-демократической модели: **hистадрут**, кибуцы, государственное планирование.
## Переворот 1977 года
**Маhапах** (מהפך) — «переворот»: **Ликуд** (הליכוד) во главе с **Менахемом Бегином** (מנחם בגין) впервые победил. Мизрахийские избиратели стали политической силой. Бегин заключил мир с Египтом.
## Фрагментация
С 1990-х — рост числа партий: секторальные (русские, арабские, ультраортодоксальные), идеологические, личностные. Электоральный барьер повышен до 3,25%, но в Кнессете всё равно 10–12 партий.
## Эра нестабильности
Пять выборов за два года (2019–2022) — беспрецедентный кризис. Коалиции становятся всё более хрупкими. Вопрос судебной реформы расколол общество. Политическая система ищет новый баланс между представительством и стабильностью.', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (95, 'history', 'Эволюция иврита — от библейского языка к разговорному', 'התפתחות העברית — משפה מקראית לשפה מדוברת', '# Эволюция иврита (התפתחות העברית)
Иврит — единственный язык в истории, «воскресший» из литургического в разговорный. Его эволюция продолжается и сегодня.
## Библейский иврит
**Иврит микраит** (עברית מקראית) — язык Танаха: богатая глагольная система, паратаксис (соединение через «вав»), ограниченная абстрактная лексика. Произношение реконструируется лингвистами.
## Мишнаитский иврит
**Иврит мишнаит** (עברית משנאית) — язык Мишны (200 г. н.э.): упрощённая глагольная система, влияние арамейского и греческого, развитие юридической терминологии.
## Средневековый иврит
Язык поэзии, философии, науки. Влияние арабского: абстрактные понятия, поэтические размеры. **Рамбам** (רמב"ם) писал философию по-арабски, но галаху — на иврите.
## Возрождение
**Элиэзер Бен-Иехуда** (אליעזר בן-יהודה) — «отец современного иврита». Создал тысячи неологизмов. «Война языков» 1913 года утвердила иврит как язык образования.
## Современный иврит
**Иврит бат-зманену** (עברית בת-זמננו) — впитал влияния идиша, арабского, русского, английского. Академия языка иврит создаёт новые слова, но разговорный язык живёт по своим законам: сокращения, сленг, переключение кодов.', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (96, 'history', 'Средневековая еврейская философия — от Саадии Гаона до Рамбама', 'הפילוסופיה היהודית בימי הביניים — מסעדיה גאון ועד הרמב"ם', '# Средневековая еврейская философия (הפילוסופיה היהודית בימי הביניים)
Средневековая еврейская философия — **hа-филосОфия hа-йеhудИт** (הפילוסופיה היהודית) — расцвела в диалоге с исламской и христианской мыслью, став мостом между античностью и Новым временем.
## Саадия Гаон
**Саадия Гаон** (סעדיה גאון, 882–942) — первый систематический еврейский философ. «Книга верований и мнений» — **Сефер hа-Эмунот ве-hа-Деот** (ספר האמונות והדעות) — попытка примирить разум и откровение. Писал по-арабски.
## Иехуда hа-Леви
**Иехуда hа-Леви** (יהודה הלוי, 1075–1141) — поэт и философ. «Кузари» (הכוזרי) — диалог, защищающий иудаизм перед лицом философии, христианства и ислама. Не разум, а опыт и традиция — основа веры.
## Рамбам (Маймонид)
**Рамбам** (רמב"ם, 1138–1204) — Моше бен Маймон — величайший средневековый еврейский мыслитель. «Путеводитель растерянных» — **Море Невухим** (מורה נבוכים) — синтез аристотелизма и иудаизма. «Мишне Тора» (משנה תורה) — кодекс еврейского закона. Рамбам сформулировал 13 принципов веры.
## Наследие
Средневековая философия заложила основы рационального иудаизма. Споры о соотношении разума и веры, философии и Галахи продолжаются в израильской академии и религиозной жизни.', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (98, 'society', 'Израиль и диаспора — сложные отношения', 'ישראל והתפוצות — יחסים מורכבים', '# Израиль и диаспора (ישראל והתפוצות)
Отношения между Израилем и еврейской **диаспорой** — **тфуцот** (תפוצות, тфуцОт) — одна из самых сложных тем в еврейском мире.
## Классический сионизм
Классический сионизм — **циОнут** (ציונות) — рассматривал **галут** (גלות, галУт) — изгнание/диаспору — как аномалию, подлежащую преодолению через алию. Бен-Гурион говорил: «сионист — тот, кто живёт в Сионе».
## Американское еврейство
Около 7 миллионов евреев в США — крупнейшая община вне Израиля. Финансовая поддержка, политическое лобби (**AIPAC**), культурные связи. Но и растущие разногласия: реформистский и консервативный иудаизм не признаются в Израиле.
## Трещины
Разногласия: вопрос «кто есть еврей?» — **ми hу йеhуди** (מי הוא יהודי), равноправие течений в иудаизме, политика по отношению к палестинцам, судебная реформа.
## Новая парадигма
Молодое поколение в диаспоре менее привязано к Израилю. Израиль ищет новые формы связи: программы **Таглит** (תגלית, Birthright), культурные обмены, совместные проекты.', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (99, 'society', 'Технологическая нация — от капельного орошения к ИИ', 'אומת הטכנולוגיה — מהשקיה בטפטוף ועד בינה מלאכותית', '# Технологическая нация (אומת הטכנולוגיה)
Израиль — одна из самых технологически продвинутых стран мира. Инновации — **хидушим** (חידושים) — не просто отрасль, а часть национальной ДНК.
## Корни инновационности
Факторы: военная необходимость, ограниченность ресурсов, культура «хуцпы» — готовности бросать вызов, мультикультурность, качественное образование, обязательная армейская служба (особенно подразделение 8200).
## Сельское хозяйство
Израиль превратил пустыню в сад. **Капельное орошение** (השקיה בטפטוף) — изобретение Симхи Бласса. **Netafim** — мировой лидер. Безгрунтовое выращивание, опреснение воды, GPS-навигация для тракторов.
## Кибербезопасность
Второе место в мире после США. Check Point, CyberArk, Wiz, SentinelOne — глобальные лидеры. **Беэр-Шева** превращается в «кибер-столицу» — **бират hа-сайбер** (בירת הסייבר).
## Медтех
**Камера-в-таблетке** (PillCam), экзоскелеты ReWalk, роботизированная хирургия Mazor. Израиль — лидер телемедицины и цифрового здравоохранения.
## Искусственный интеллект
Более 1800 стартапов в сфере ИИ. Центры разработки Google, Microsoft, Apple, Intel. Израиль формирует будущее технологий мирового масштаба.', 6);
INSERT INTO public.culture_articles (id, category, title_ru, title_he, content_md, level_id) VALUES (100, 'society', 'Будущее иврита — язык в цифровую эпоху', 'עתיד העברית — שפה בעידן הדיגיטלי', '# Будущее иврита (עתיד העברית)
Иврит — язык 10 миллионов носителей — стоит перед уникальными вызовами и возможностями цифровой эпохи.
## Английский вызов
**Англизация** — **hитангелут** (התאנגלות) — проникновение английского в повседневную речь. В хайтеке, академии, молодёжном сленге английские слова вытесняют ивритские. «Это challenge» вместо «это этгАр» (אתגר). Академия борется, предлагая альтернативы: **гишур** (גישור) вместо «бриджинг».
## Цифровой иврит
Интернет создал новые формы языка: сокращения в мессенджерах — **бс"д** (בס"ד, с Божьей помощью), **ахлА** (אחלה, отлично). Эмодзи частично заменяют слова. NLP-технологии для иврита развиваются: GPT-модели на иврите, голосовые ассистенты.
## Арабское влияние
**Арабский сленг** проникает через армию и улицу: **яла** (יאללה), **ахлА** (אחלא), **саббаба** (סבבה), **халАс** (חלאס). Это обогащает язык, но вызывает споры у пуристов.
## Русское влияние
Миллион русскоязычных привнесли свои словечки: **капАра** обрело новые коннотации, русские мемы переводятся на иврит.
## Перспективы
Иврит — живой, динамичный язык, доказавший жизнеспособность. Его будущее зависит от баланса между открытостью к влияниям и сохранением уникальной семитской структуры. Как язык, «воскресший из мёртвых», он обречён на вечное обновление.', 6);
